// v47：追問配置（模組開關 + 每筆解讀綁幾次免費追問）
// KV key: followup_config → JSON
//   { perResult: 1, modules: { role:true, pushback:true, boundary:true, levels:true, depth:true, errorfix:true, manipulation:true } }
const FOLLOWUP_MODULE_KEYS = ['role','pushback','boundary','levels','depth','errorfix','manipulation'];
const DEFAULT_FU_PER_RESULT = 1;
function _defaultFuModules() {
  var m = {};
  FOLLOWUP_MODULE_KEYS.forEach(function(k){ m[k] = true; });
  return m;
}
async function getFollowupConfig(env) {
  const fallback = { perResult: DEFAULT_FU_PER_RESULT, modules: _defaultFuModules() };
  if (!env.RATE_KV) return fallback;
  try {
    const raw = await env.RATE_KV.get('followup_config');
    if (!raw) return fallback;
    const cfg = JSON.parse(raw);
    const perResult = (typeof cfg.perResult === 'number' && cfg.perResult >= 0 && cfg.perResult <= 100)
      ? Math.floor(cfg.perResult) : DEFAULT_FU_PER_RESULT;
    const modules = _defaultFuModules();
    if (cfg.modules && typeof cfg.modules === 'object') {
      FOLLOWUP_MODULE_KEYS.forEach(function(k){
        if (typeof cfg.modules[k] === 'boolean') modules[k] = cfg.modules[k];
      });
    }
    return { perResult: perResult, modules: modules };
  } catch(_) { return fallback; }
}

