// v49：Haiku 4.5 Extended Thinking 配置
// KV key: haiku_thinking_config → JSON
//   { enabled: true, budgetTokens: 4000, includeFollowup: true }
// - enabled:         全域開關（false = 關閉所有 Haiku thinking，退回原本行為）
// - budgetTokens:    思考預算（1024-8000，官方要求最小 1024）
// - includeFollowup: 追問是否也開 thinking（false = 追問不開省成本）
// 依據：Haiku 4.5 是第一個支援 extended thinking 的 Haiku 模型；
//       第三方 benchmark：thinking 開後品質 6.20 → 7.29，贏率 58%；
//       命理推理屬於 multi-step reasoning，官方歸類 intelligence-sensitive。
// ═══════════════════════════════════════════════════════════════
const DEFAULT_HAIKU_THINKING = { enabled: true, budgetTokens: 4000, includeFollowup: true };
async function getHaikuThinkingConfig(env) {
  if (!env.RATE_KV) return Object.assign({}, DEFAULT_HAIKU_THINKING);
  try {
    const raw = await env.RATE_KV.get('haiku_thinking_config');
    if (!raw) return Object.assign({}, DEFAULT_HAIKU_THINKING);
    const cfg = JSON.parse(raw);
    const enabled = (typeof cfg.enabled === 'boolean') ? cfg.enabled : DEFAULT_HAIKU_THINKING.enabled;
    var budget = DEFAULT_HAIKU_THINKING.budgetTokens;
    if (typeof cfg.budgetTokens === 'number' && cfg.budgetTokens >= 1024 && cfg.budgetTokens <= 8000) {
      budget = Math.floor(cfg.budgetTokens);
    }
    const includeFollowup = (typeof cfg.includeFollowup === 'boolean') ? cfg.includeFollowup : DEFAULT_HAIKU_THINKING.includeFollowup;
    return { enabled: enabled, budgetTokens: budget, includeFollowup: includeFollowup };
  } catch(_) { return Object.assign({}, DEFAULT_HAIKU_THINKING); }
}

