// ═══════════════════════════════════════════════════════════════
// v62c：Opus 4.7 Task Budget 配置（admin 可切換）
// 依據：https://platform.claude.com/docs/en/about-claude/models/whats-new-claude-4-7
// KV key: opus47_task_budget_config → JSON { enabled: boolean, tokens: number }
// 官方：「model sees a running countdown and uses it to prioritize work and finish gracefully」
// 命理場景用途：解決 AI 寫到一半覺得夠了就停、第三層漏寫的問題
//   AI 看到 task_budget 倒數會主動規劃「還要寫第三層」
// 預設關閉（beta 先實測）。開啟後建議 tokens: 32000-64000
//   太低：AI 會裁切，可能反效果
//   太高：失去引導作用
// 只對 Opus 4.7 有效（其他模型不支援）
// ═══════════════════════════════════════════════════════════════
const DEFAULT_OPUS47_TASK_BUDGET = { enabled: true, tokens: 32000 };  // v64.E:預設改開,實測對命理品質有效益(讓 AI 主動規劃三層收完)
async function getOpus47TaskBudgetConfig(env) {
  if (!env || !env.RATE_KV) return Object.assign({}, DEFAULT_OPUS47_TASK_BUDGET);
  try {
    const raw = await env.RATE_KV.get('opus47_task_budget_config');
    if (!raw) return Object.assign({}, DEFAULT_OPUS47_TASK_BUDGET);
    const cfg = JSON.parse(raw);
    const enabled = (cfg.enabled === true);
    const rawTokens = typeof cfg.tokens === 'number' ? cfg.tokens : DEFAULT_OPUS47_TASK_BUDGET.tokens;
    // 官方下限 20000，上限 128000，安全範圍 20000-96000
    const tokens = Math.min(96000, Math.max(20000, Math.floor(rawTokens)));
    return { enabled: enabled, tokens: tokens };
  } catch(_) { return Object.assign({}, DEFAULT_OPUS47_TASK_BUDGET); }
}

// ═══════════════════════════════════════════════════════════════════════════
// 🌌 高精度星曆 helper（內嵌版，不能 require module）
// 提供 calcPlanetsHighPrecision(year, month, day, hour, minute, tz, env, mode)
// Provider 順序：KV 快取 → AstrologyAPI → JPL Horizons → Meeus fallback
// ═══════════════════════════════════════════════════════════════════════════

function _ephCacheKey(year, month, day, hour, minute, tz, mode) {
  return 'eph:' + (mode || 'tropical') + ':' + year + '-' + String(month).padStart(2,'0')
    + '-' + String(day).padStart(2,'0') + 'T' + String(hour).padStart(2,'0')
    + ':' + String(minute).padStart(2,'0') + '+' + (tz || 0);
}

function _ephLocalToJD(year, month, day, hour, minute, tz) {
  const utHour = (hour || 0) - (tz || 0);
  const utMinute = minute || 0;
  let Y = year, M = month;
  if (M <= 2) { Y--; M += 12; }
  const A = Math.floor(Y / 100);
  const B = 2 - A + Math.floor(A / 4);
  return Math.floor(365.25 * (Y + 4716))
    + Math.floor(30.6001 * (M + 1))
    + day + (utHour + utMinute / 60) / 24 + B - 1524.5;
}

async function _ephFromAstrologyAPI(year, month, day, hour, minute, tz, apiKey, apiSecret) {
  const url = 'https://json.astrologyapi.com/v1/planets/tropical';
  const auth = btoa(apiKey + ':' + apiSecret);
  const body = { day: day, month: month, year: year, hour: hour, min: minute,
                 lat: 25.0330, lon: 121.5654, tzone: tz };
  const resp = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Basic ' + auth },
    body: JSON.stringify(body)
  });
  if (!resp.ok) throw new Error('AstrologyAPI HTTP ' + resp.status);
  const data = await resp.json();
  const result = {};
  const nameMap = { sun:'Sun', moon:'Moon', mercury:'Mercury', venus:'Venus',
                    mars:'Mars', jupiter:'Jupiter', saturn:'Saturn',
                    uranus:'Uranus', neptune:'Neptune', pluto:'Pluto',
                    rahu:'Rahu', ketu:'Ketu', 'true node':'Rahu' };
  if (Array.isArray(data)) {
    data.forEach(p => {
      const rawName = (p.name || p.planet || '').toLowerCase();
      const name = nameMap[rawName] || rawName;
      const lon = p.fullDegree || p.full_degree || p.longitude;
      if (name && lon != null) result[name] = { lon: parseFloat(lon), lat: 0 };
    });
  }
  return result;
}

async function _ephFromJPLHorizons(jd, planet) {
  const idMap = { Sun:'10', Moon:'301', Mercury:'199', Venus:'299',
                  Mars:'499', Jupiter:'599', Saturn:'699',
                  Uranus:'799', Neptune:'899' };
  const id = idMap[planet];
  if (!id) return null;
  const url = 'https://ssd.jpl.nasa.gov/api/horizons.api?format=text'
    + '&COMMAND=%27' + id + '%27'
    + '&MAKE_EPHEM=YES&EPHEM_TYPE=OBSERVER&CENTER=%27500@399%27'
    + '&START_TIME=%27JD' + jd + '%27&STOP_TIME=%27JD' + (jd + 0.001) + '%27'
    + '&STEP_SIZE=%271%27&QUANTITIES=%2731%27&CSV_FORMAT=YES';
  const resp = await fetch(url, { method: 'GET' });
  if (!resp.ok) throw new Error('JPL HTTP ' + resp.status);
  const text = await resp.text();
  const lines = text.split('\n');
  let inData = false;
  for (const line of lines) {
    if (line.indexOf('$$SOE') >= 0) { inData = true; continue; }
    if (line.indexOf('$$EOE') >= 0) break;
    if (inData && line.trim()) {
      const cols = line.split(',').map(s => s.trim());
      if (cols.length >= 4) {
        const lon = parseFloat(cols[3]);
        const lat = cols.length >= 5 ? parseFloat(cols[4]) : 0;
        if (!isNaN(lon)) return { lon: lon, lat: isNaN(lat) ? 0 : lat };
      }
    }
  }
  throw new Error('JPL parse fail');
}

function _ephMeeusFallback(jd) {
  const T = (jd - 2451545.0) / 36525.0;
  const _RAD = Math.PI / 180;
  function _norm(x) { x = x % 360; return x < 0 ? x + 360 : x; }
  const L0 = 280.46646 + 36000.76983 * T;
  const M = (357.52911 + 35999.05029 * T) * _RAD;
  const C = (1.914602 - 0.004817 * T) * Math.sin(M) + 0.019993 * Math.sin(2 * M);
  const sunLon = _norm(L0 + C);
  const moonL = 218.3164477 + 481267.88123421 * T;
  const moonD = (297.8501921 + 445267.1114034 * T) * _RAD;
  const moonM = (134.9633964 + 477198.8675055 * T) * _RAD;
  const moonLon = _norm(moonL + 6.289 * Math.sin(moonM) - 1.274 * Math.sin(moonM - 2*moonD)
    + 0.658 * Math.sin(2*moonD) - 0.186 * Math.sin(M));
  const rahuLon = _norm(125.0445550 - 1934.1361849 * T);
  return {
    Sun: { lon: sunLon, lat: 0 },
    Moon: { lon: moonLon, lat: 0 },
    Rahu: { lon: rahuLon, lat: 0 },
    Ketu: { lon: _norm(rahuLon + 180), lat: 0 },
    _fallback: true
  };
}

async function calcPlanetsHighPrecision(year, month, day, hour, minute, tz, env, mode) {
  mode = mode || 'tropical';
  const jd = _ephLocalToJD(year, month, day, hour, minute, tz);
  const ck = _ephCacheKey(year, month, day, hour, minute, tz, mode);

  // 1. KV 快取
  if (env && env.RATE_KV) {
    try {
      const raw = await env.RATE_KV.get(ck);
      if (raw) {
        const cached = JSON.parse(raw);
        return { source: cached._source || 'cache', jd: jd, planets: cached.planets || cached, mode: mode };
      }
    } catch(_) {}
  }

  // 2. AstrologyAPI
  if (env && env.ASTROLOGY_API_KEY && env.ASTROLOGY_API_SECRET) {
    try {
      const planets = await _ephFromAstrologyAPI(year, month, day, hour, minute, tz,
        env.ASTROLOGY_API_KEY, env.ASTROLOGY_API_SECRET);
      if (planets && Object.keys(planets).length >= 7) {
        if (env.RATE_KV) {
          try { await env.RATE_KV.put(ck, JSON.stringify({ _source: 'astrologyapi', planets: planets }), { expirationTtl: 86400 }); } catch(_) {}
        }
        return { source: 'astrologyapi', jd: jd, planets: planets, mode: mode };
      }
    } catch(e) { console.warn('AstrologyAPI:', e && e.message); }
  }

  // 3. JPL Horizons
  if (env && env.USE_JPL_HORIZONS === 'true') {
    try {
      const list = ['Sun','Moon','Mercury','Venus','Mars','Jupiter','Saturn'];
      const results = await Promise.all(list.map(p => _ephFromJPLHorizons(jd, p).catch(() => null)));
      const planets = {};
      list.forEach((name, i) => { if (results[i]) planets[name] = results[i]; });
      const T = (jd - 2451545.0) / 36525.0;
      const rahuRaw = 125.0445550 - 1934.1361849 * T + 0.0020762 * T*T;
      const rahuLon = ((rahuRaw % 360) + 360) % 360;
      planets.Rahu = { lon: rahuLon, lat: 0 };
      planets.Ketu = { lon: (rahuLon + 180) % 360, lat: 0 };
      if (Object.keys(planets).length >= 7) {
        if (env.RATE_KV) {
          try { await env.RATE_KV.put(ck, JSON.stringify({ _source: 'jpl_horizons', planets: planets }), { expirationTtl: 86400 }); } catch(_) {}
        }
        return { source: 'jpl_horizons', jd: jd, planets: planets, mode: mode };
      }
    } catch(e) { console.warn('JPL:', e && e.message); }
  }

  // 4. Meeus fallback
  return { source: 'meeus_fallback', jd: jd, planets: _ephMeeusFallback(jd), mode: mode };
}

// ═══════════════════════════════════════════════════════════════════════════
// v62d：Advisor Tool 配置（admin 可切換）
// 依據：https://platform.claude.com/docs/en/agents-and-tools/tool-use/advisor-tool
// KV key: advisor_tool_config → JSON {
//   enabled: boolean,      // 總開關
//   advisorModel: 'claude-opus-4-7' | 'claude-opus-4-6',  // advisor 用哪個模型
//   maxUses: number,       // 每次請求最多呼叫幾次 advisor（預設 2，命理場景 2-3 最佳）
//   enableCaching: boolean // advisor 端 prompt caching（3+ 次才回本）
// }
// 官方數據：Sonnet + Opus advisor → 準確度 +2.7%、成本 -11.9%（SWE-bench）
// 命理用途：會員線 Sonnet 4.6 執行 + Opus 4.7 advisor = 接近付費線品質
// 模型相容性限制：
//   - Haiku 4.5 / Sonnet 4.6 / Opus 4.6 / Opus 4.7 可當 executor
//   - advisor 必須 ≥ executor 的能力（Sonnet 不能當 Opus 的 advisor）
//   - 建議 advisor 統一用 claude-opus-4-7
// 預設：關閉（beta 先實測）
// ═══════════════════════════════════════════════════════════════════════════
const DEFAULT_ADVISOR_TOOL = {
  enabled: false,
  advisorModel: 'claude-opus-4-7',
  maxUses: 2,
  enableCaching: false
};
const ADVISOR_MODEL_ALLOWED = ['claude-opus-4-7', 'claude-opus-4-6'];
async function getAdvisorToolConfig(env) {
  if (!env || !env.RATE_KV) return Object.assign({}, DEFAULT_ADVISOR_TOOL);
  try {
    const raw = await env.RATE_KV.get('advisor_tool_config');
    if (!raw) return Object.assign({}, DEFAULT_ADVISOR_TOOL);
    const cfg = JSON.parse(raw);
    const enabled = (cfg.enabled === true);
    const advisorModel = (typeof cfg.advisorModel === 'string' && ADVISOR_MODEL_ALLOWED.indexOf(cfg.advisorModel) >= 0)
      ? cfg.advisorModel : DEFAULT_ADVISOR_TOOL.advisorModel;
    const rawMaxUses = typeof cfg.maxUses === 'number' ? cfg.maxUses : DEFAULT_ADVISOR_TOOL.maxUses;
    const maxUses = Math.min(5, Math.max(1, Math.floor(rawMaxUses))); // 安全範圍 1-5
    const enableCaching = (cfg.enableCaching === true);
    return { enabled: enabled, advisorModel: advisorModel, maxUses: maxUses, enableCaching: enableCaching };
  } catch(_) { return Object.assign({}, DEFAULT_ADVISOR_TOOL); }
}

// ═══════════════════════════════════════════════════════════════════════════
// v62e：Assistant Prefill 配置（admin 可切換）
// 依據：Anthropic 官方 Prompt Engineering - prefill Claude's response
// KV key: prefill_config → JSON { enabled: boolean, prefillText: string }
// 原理：預填 assistant 回應開頭字元，強制 AI 從該字元接續輸出
//   prefill '{' → AI 只能從 JSON 開始，沒有 markdown fence 或前綴雜訊
//   命理用途：塔羅/開鑰/七維度 JSON 輸出不會 parse 失敗
// 相容性（官方硬性）：
//   - Opus 4.7 / Opus 4.6：不支援 → 400 error（只對 Sonnet/Haiku 適用）
//   - Sonnet 4.6 / Haiku 4.5：支援
// 預設：關閉（先實測一週，確認 Sonnet/Haiku 相容性後再開）
// ═══════════════════════════════════════════════════════════════════════════
const DEFAULT_PREFILL = {
  enabled: false,
  prefillText: '{'  // 預設 JSON 開頭
};
async function getPrefillConfig(env) {
  if (!env || !env.RATE_KV) return Object.assign({}, DEFAULT_PREFILL);
  try {
    const raw = await env.RATE_KV.get('prefill_config');
    if (!raw) return Object.assign({}, DEFAULT_PREFILL);
    const cfg = JSON.parse(raw);
    const enabled = (cfg.enabled === true);
    // 安全限制：prefillText 不可超過 10 字元（避免誤設整段 prompt）
    const prefillText = (typeof cfg.prefillText === 'string' && cfg.prefillText.length > 0 && cfg.prefillText.length <= 10)
      ? cfg.prefillText : DEFAULT_PREFILL.prefillText;
    return { enabled: enabled, prefillText: prefillText };
  } catch(_) { return Object.assign({}, DEFAULT_PREFILL); }
}

