async function getV62UpgradesConfig(env) {
  if (!env || !env.RATE_KV) return Object.assign({}, DEFAULT_V62_UPGRADES);
  try {
    const raw = await env.RATE_KV.get('v62_prompt_upgrades');
    if (!raw) return Object.assign({}, DEFAULT_V62_UPGRADES);
    const cfg = JSON.parse(raw);
    const merged = {};
    Object.keys(DEFAULT_V62_UPGRADES).forEach(k => {
      merged[k] = (typeof cfg[k] === 'boolean' || typeof cfg[k] === 'number') ? cfg[k] : DEFAULT_V62_UPGRADES[k];
    });
    return merged;
  } catch(_) { return Object.assign({}, DEFAULT_V62_UPGRADES); }
}

