  '  ✗ 說「西方系統不適用」或「塔羅不能算這個」\n' +
  '    → 錯,塔羅有完整對應牌陣,重寫\n' +
  '  ✗ 健康類問題直接斷定具體疾病或建議治療方案 → 越界,重寫\n' +
  '\n' +
  '═══ 七維度交叉引擎 結束 ═══\n';


// ═══════════════════════════════════════════════════════════════════════════
// 路由器 — 偵測用戶問題屬於哪一大類,決定要注入哪個引擎模組
// ═══════════════════════════════════════════════════════════════════════════

function detectV64FCategory(userQuery) {
  if (!userQuery || typeof userQuery !== 'string') return [];
  var q = userQuery.toLowerCase();
  var categories = [];

  // 感情/婚姻 (LOVE) — 已單獨成檔 V64_F_ENGINE_CORE_LOVE_SAMPLE
  if (/桃花|結婚|離婚|配偶|伴侶|感情|婚姻|復合|相親|曖昧|分手|外遇|第三者|小三|戀愛|情人|男友|女友|對象|姻緣|單身/.test(userQuery))
    categories.push('LOVE');

  // 事業/學業 (CAREER)
  if (/工作|事業|職業|升職|升遷|轉職|跳槽|創業|開店|公司|老闆|主管|升學|考試|學業|讀書|留學|考運|職場|職涯|面試|履歷/.test(userQuery))
    categories.push('CAREER');

  // 財運/物質 (WEALTH)
  if (/財運|賺錢|收入|投資|理財|股票|偏財|彩券|賭博|樂透|房產|不動產|買房|買地|失物|遺失|被偷|金錢|錢財|破財|發財|致富/.test(userQuery))
    categories.push('WEALTH');

  // 健康/身體 (HEALTH)
  if (/健康|身體|生病|疾病|手術|開刀|康復|心理|憂鬱|焦慮|失眠|體質|體力|體重|減肥|懷孕|生育|不孕|過敏|慢性病/.test(userQuery))
    categories.push('HEALTH');

  // 人際/六親 (RELATION)
  if (/父母|父親|母親|爸爸|媽媽|爸|媽|長輩|子女|小孩|兒女|孩子|兒子|女兒|孫子|孫女|兄弟|姐妹|姊妹|手足|哥哥|姊姊|姐姐|弟弟|妹妹|嫂子|弟妹|姊夫|妹夫|朋友|同事|合夥|上司|下屬|部屬|主管|貴人|小人|親戚|親人|家人|婆婆|公公|岳父|岳母|媳婦|女婿|繼父|繼母/.test(userQuery))
    categories.push('RELATION');

  // 遷移/抉擇 (CHOICE)
  if (/搬家|出國|移民|留學|遷移|出行|旅行|該不該|要不要|選哪個|哪個好|還是B|還是另|還是其|該選|怎麼選|該不該選|抉擇|決定|行人|何時回|在哪|方位|風水|二選一|三選一|對比|比較|猶豫/.test(userQuery)
      || /選.{1,8}還是/.test(userQuery)
      || /要.{1,4}還是/.test(userQuery)
      || /A.{0,3}還是.{0,3}B/.test(userQuery))
    categories.push('CHOICE');

  // 預設(整體運勢)
  if (categories.length === 0)
    categories.push('LIFE');

  // 自身運勢類別也可單獨偵測(可能與其他類別並存)
  if (/流年|運勢|今年|明年|大運|流月|整體|吉凶|何時走運|衰運|運氣/.test(userQuery)
      && categories.indexOf('LIFE') === -1) {
    categories.push('LIFE');
  }

  return categories;
}

// 根據類別返回對應引擎內容(單個或多個拼接)
function getV64FEngineByCategory(categories) {
  var engineMap = {
    'LOVE':     V64_F_ENGINE_CORE_LOVE_SAMPLE,  // 感情(已存在)
    'LIFE':     V64_F_ENGINE_LIFE,
    'CAREER':   V64_F_ENGINE_CAREER,
    'WEALTH':   V64_F_ENGINE_WEALTH,
    'HEALTH':   V64_F_ENGINE_HEALTH,
    'RELATION': V64_F_ENGINE_RELATION,
    'CHOICE':   V64_F_ENGINE_CHOICE
  };

  var combined = '';
  for (var i = 0; i < categories.length; i++) {
    var cat = categories[i];
    if (engineMap[cat]) {
      combined += engineMap[cat];
    }
  }

  // 加上共用尾段(只加一次即可)
  if (combined.length > 0) {
    combined += V64_F_ENGINE_FOOTER;
  }

  return combined;
}


