  '・我有沒有檢查地支根?(沒檢查就直接斷從格 = 違規,重寫)\n' +
  '・我寫的用神跟 payload 的 b.fav 一致嗎?(不一致 → 你錯了,以 payload 為準)\n' +
  '・行運判斷有沒有對應正格/從格的差異?(混用 = 邏輯崩潰,重寫)\n' +
  '\n' +
  '═══════════════════════════════════════════════════════════════════════\n';

// ═══════════════════════════════════════════════════════════════
// v50：buildHardFactsAnchor — 命主硬事實錨點(防 hallucination 核心機制)
// ═══════════════════════════════════════════════════════════════
// 問題背景:
//   bazi.js/ziwei.js/tarot.js 把日主、大運、配偶宮等硬資料都算對並傳給 AI,
//   但在 52 萬字 payload 的中段,AI 注意力稀釋(lost-in-the-middle),
//   長 thinking 放大自由聯想,會編造不存在的大運名稱、搞錯日主五行。
//
// 解法:
//   把 10 條 AI 最容易搞錯的硬事實,抽成 500 字內的錨點,放在 prompt 最前面
//   (attention 最高的 U 型曲線左端),並明寫「禁止自創」。
//
// 抽哪些欄位(按 AI 最常編錯的優先排):
//   1. 日主(天干+五行)
//   2. 四柱完整八字
//   3. 當前大運(明確註明是哪一柱+年齡範圍)
//   4. 用神/忌神
//   5. 今年流年
//   6. 配偶宮(日支)
//   7. 紫微命宮主星
//   8. 紫微夫妻宮主星(感情題)
//   9. 塔羅結果牌
// ═══════════════════════════════════════════════════════════════
function buildHardFactsAnchor(dims) {
  if (!dims || typeof dims !== 'object') return '';
  const lines = [];
  const bz = dims.bazi || {};
  const zw = dims.ziwei || {};
  const tr = dims.tarot || {};
  const vd = dims.vedic || {};
  const nt = dims.natal || {};
  const nm = dims.name || {};

  // ── 八字硬事實 ──
  if (bz.dayMaster || bz.fourPillars) {
    lines.push('【八字】');
    if (bz.fourPillars) lines.push('四柱: ' + bz.fourPillars);
    if (bz.dayMaster) lines.push('日主: ' + bz.dayMaster + ' ← 寫作時提到日主只能用這個值,禁止自創別的天干');
    if (bz.strong != null) lines.push('身強弱: ' + (bz.strong ? '身強' : '身弱'));
    if (bz.favEls) lines.push('用神: ' + bz.favEls);
    if (bz.unfavEls) lines.push('忌神: ' + bz.unfavEls);

    // 當前大運 — 從 allDayun 抽出 ★當前 那一項(最可靠),fallback 用 dyDetail
    let currentDayun = '';
    if (bz.allDayun && typeof bz.allDayun === 'string') {
      const parts = bz.allDayun.split('；');
      const cur = parts.find(p => p.indexOf('★當前') >= 0);
      if (cur) currentDayun = cur.trim();
    }
    if (!currentDayun && bz.dyDetail) {
      // dyDetail 可能是字串或物件,都轉字串取前 80 字
      currentDayun = (typeof bz.dyDetail === 'string' ? bz.dyDetail : JSON.stringify(bz.dyDetail)).slice(0, 100);
    }
    if (currentDayun) lines.push('當前大運: ' + currentDayun + ' ← 寫作時提到大運只能引用這個,禁止自創其他柱名');

    // 今年流年
    if (bz.lnDetail) {
      const ln = (typeof bz.lnDetail === 'string' ? bz.lnDetail : JSON.stringify(bz.lnDetail)).slice(0, 100);
      lines.push('今年流年: ' + ln);
    }

    // 配偶宮(日支)—從 fourPillars 抽
    if (bz.fourPillars && typeof bz.fourPillars === 'string') {
      const m = bz.fourPillars.match(/日:([^\s]+)/);
      if (m && m[1]) {
        const dayPillar = m[1];
        // 取日支(第二字)
        const dayZhi = dayPillar.length >= 2 ? dayPillar.charAt(1) : '';
        if (dayZhi) lines.push('配偶宮(日支): ' + dayZhi + ' ← 提到配偶宮只能說這個地支,禁止說其他字');
      }
    }

    // 格局
    if (bz.specialGe) lines.push('特殊格局: ' + bz.specialGe);
    else if (bz.geJu) lines.push('正格: ' + bz.geJu);

    // 調候(申月乙木這類關鍵調候信息)
    if (bz.tiaohou) {
      const th = (typeof bz.tiaohou === 'string' ? bz.tiaohou : JSON.stringify(bz.tiaohou)).slice(0, 120);
      lines.push('調候: ' + th);
    }
  }

  // ── 紫微硬事實 ──
  if (zw.mingStars || (zw.keyPalaces && typeof zw.keyPalaces === 'string' && zw.keyPalaces.length > 0)) {
    lines.push('');
    lines.push('【紫微】');
    if (zw.mingStars) lines.push('命宮主星: ' + zw.mingStars + ' ← 提到命宮主星只能引用這個');
    if (zw.shenGong) lines.push('身宮: ' + zw.shenGong);
    // 從 keyPalaces 找夫妻宮
    if (zw.keyPalaces && typeof zw.keyPalaces === 'string') {
      const kp = zw.keyPalaces;
      // 通常格式像 "夫妻宮(武曲破軍...)" 或類似
      const spouseMatch = kp.match(/夫妻[宮:]*\s*[\[\(]?([^\]\)\|、；]+)/);
      if (spouseMatch && spouseMatch[1]) lines.push('夫妻宮: ' + spouseMatch[1].trim() + ' ← 感情題提到夫妻宮只能引用這個');
    }
    if (zw.dxDetail) {
      const dx = (typeof zw.dxDetail === 'string' ? zw.dxDetail : JSON.stringify(zw.dxDetail)).slice(0, 100);
      lines.push('當前大限: ' + dx);
    }
  }

  // ── 塔羅硬事實 ──
  if (tr.outcomeCard || tr.spreadType) {
    lines.push('');
    lines.push('【塔羅】');
    if (tr.spreadType) lines.push('牌陣: ' + tr.spreadType);
    if (tr.outcomeCard) lines.push('結果牌: ' + tr.outcomeCard + ' ← 提到結果牌只能用這張');
    if (tr.uprightRatio != null) lines.push('正逆比: ' + tr.uprightRatio);
  }

  // ── 吠陀硬事實 (v53 A4 新增) ──
  // 吠陀 Dasha 層級是 AI 最容易編的——Mahadasha/Antardasha/Pratyantardasha 三層主星名稱
  if (vd.dasha || vd.moon || vd.sadeSati) {
    lines.push('');
    lines.push('【吠陀】');
    if (vd.lagna) lines.push('上升(Lagna): ' + String(vd.lagna).slice(0, 60) + ' ← 提到吠陀上升只能用這個');
    if (vd.moon) lines.push('月亮星座/Nakshatra: ' + String(vd.moon).slice(0, 80) + ' ← 提到月亮Nakshatra只能用這個,禁止自創別的星宿');
    if (vd.dasha) {
      const ds = String(vd.dasha).slice(0, 80) + (vd.dashaEnd ? ' (結束於' + vd.dashaEnd + ')' : '');
      lines.push('當前大運(Mahadasha): ' + ds + ' ← 提到吠陀大運主星名稱只能用這個,禁止換成其他行星');
    }
    if (vd.subDasha) {
      const sd = String(vd.subDasha).slice(0, 80) + (vd.subDashaEnd ? ' (結束於' + vd.subDashaEnd + ')' : '');
      lines.push('當前副運(Antardasha): ' + sd + ' ← 提到副運主星只能用這個');
    }
    if (vd.sadeSati) lines.push('Sade Sati 狀態: ' + String(vd.sadeSati).slice(0, 80) + ' ← 提到土星7.5年考驗期只能引用這個描述');
    if (vd.yogas) lines.push('已成立 Yoga 格局: ' + String(vd.yogas).slice(0, 120) + ' ← 斷言任何 Raj/Dhana/Gaja Kesari 等格局,只能引用這裡列的,不在清單=不能說有');
    if (vd.gandanta) lines.push('Gandanta 業力結點: ' + String(vd.gandanta).slice(0, 60));
  }

  // ── 西洋硬事實 (v53 A4 新增) ──
  // 西占 transit 是 AI 最愛套用「常識」的地方——必須鎖定真正傳來的欄位
  if (nt.asc || nt.transits) {
    lines.push('');
    lines.push('【西洋星盤】');
    if (nt.asc) lines.push('上升星座: ' + String(nt.asc).slice(0, 40) + ' ← 提到西占上升只能用這個');
    if (nt.mc) lines.push('MC(天頂): ' + String(nt.mc).slice(0, 40) + ' ← 提到 MC 只能用這個');
    if (nt.transits) lines.push('當前外行星行運: ' + String(nt.transits).slice(0, 140) + ' ← 提到土星/木星/天王/冥王行運到哪宮,只能引用這裡;不在清單=不能斷言有');
    if (nt.profection) lines.push('今年小限(Profection): ' + String(nt.profection).slice(0, 60));
    if (nt.progressions) lines.push('次限推運: ' + String(nt.progressions).slice(0, 80));
  }

  // ── 姓名×八字關聯硬事實 (v53 A4 新增) ──
  // 人格五行跟八字喜忌的對應——這是姓名學最常斷錯的地方
  if (nm.geVsFav || nm.sanCai) {
    lines.push('');
    lines.push('【姓名】');
    if (nm.sanCai) lines.push('三才配置: ' + String(nm.sanCai).slice(0, 60) + ' ← 提到三才只能用這個');
    if (nm.geVsFav) lines.push('五格vs八字喜用: ' + String(nm.geVsFav).slice(0, 160) + ' ← 判「名字幫你/拖你」必須引用這裡,不能憑感覺');
    if (nm.renGeShuLi) lines.push('人格數理: ' + String(nm.renGeShuLi).slice(0, 40) + ' ← 人格是姓名學核心,佔判斷40%');
    if (nm.zodiac) lines.push('生肖姓名學: ' + String(nm.zodiac).slice(0, 80) + ' ← 提到生肖喜忌偏旁只能引用這個');
  }

  // ── 梅花硬事實 (v56 新增) ──
  // 梅花最常被搞錯的是體卦/用卦誰是誰、本卦變卦卦名、動爻位置
  // 尤其 Opus 4.7 lost-in-the-middle 加劇時，超長 context 中段 AI 容易張冠李戴
  const mh = dims.meihua || {};
  if (mh.benName || mh.tiGName || mh.tiYong) {
    lines.push('');
    lines.push('【梅花】');
    if (mh.benName) lines.push('本卦: ' + String(mh.benName).slice(0, 20) + ' ← 提到本卦卦名只能用這個');
    if (mh.bianName) lines.push('變卦: ' + String(mh.bianName).slice(0, 20) + ' ← 提到變卦卦名只能用這個');
    if (mh.tiGName) lines.push('體卦: ' + String(mh.tiGName).slice(0, 30) + ' ← 體=問卦人本身,提到體卦只能用這個');
    if (mh.yoGName) lines.push('用卦: ' + String(mh.yoGName).slice(0, 30) + ' ← 用=被問對象/事情');
    if (mh.dongYao) lines.push('動爻: ' + String(mh.dongYao).slice(0, 15) + ' ← 提到動爻位置只能用這個數字');
    if (mh.tiYong) lines.push('體用關係: ' + String(mh.tiYong).slice(0, 50) + ' ← 感情/事業定位只能用這個');
    if (mh.tiStrength) lines.push('體卦旺衰: ' + String(mh.tiStrength).slice(0, 20));
    if (mh.yongStrength) lines.push('用卦旺衰: ' + String(mh.yongStrength).slice(0, 20));
    if (mh.timingTriple && mh.timingTriple.intersection) {
      lines.push('三法交集應期: ' + String(mh.timingTriple.intersection).slice(0, 50) +
                 ' (信心' + (mh.timingTriple.confidence || '—') + ') ← 講月份只能用這個,不准自算');
    }
  }

  if (!lines.length) return '';

  return '═══ 命主核心事實(最高優先級,引用鐵律,禁止自創)═══\n'
       + '下列每一項都是 bazi.js/ziwei.js/tarot.js/jyotish/natal/name 已經精確計算的結果,不需要你重新推導。\n'
       + '寫作時提到任何命盤元素(日主/四柱/大運/用神/忌神/配偶宮/主星/夫妻宮/牌面/Dasha 主星/Nakshatra/外行星行運/人格五行),\n'
       + '必須嚴格引用下列數值。禁止自創、禁止腦補、禁止改名。\n'
       + '如果本區塊沒列出的欄位,才去看下面完整 dims 資料。\n\n'
       + lines.join('\n')
       + '\n\n═══ 引用規則(若違反=hallucination,必須重寫)═══\n'
       + '① 提到日主 = 上方「日主」欄位的天干+五行。\n'
       + '② 提到當前大運柱名 = 上方「當前大運」欄位抽出的干支,不准自創「丙辰」「戊申」這類不在清單裡的名稱。\n'
       + '③ 提到配偶宮 = 上方「配偶宮(日支)」的地支,不准換成其他字。\n'
       + '④ 提到紫微命宮/夫妻宮主星 = 上方紫微欄位的值。\n'
       + '⑤ 提到塔羅結果牌 = 上方「結果牌」欄位。\n'
       + '⑥ 提到吠陀大運/副運主星(Mahadasha/Antardasha) = 上方吠陀欄位的值,禁止自創 Saturn/Jupiter/Mercury 等主星名稱。\n'
       + '⑦ 提到吠陀月亮 Nakshatra = 上方吠陀欄位的星宿名,禁止改成其他 27 宿之一。\n'
       + '⑧ 斷言任何吠陀 Yoga 格局(Raj Yoga/Dhana Yoga/Gaja Kesari 等) = 必須在上方「已成立 Yoga 格局」清單裡看到;不在清單 = 不能斷言「你有 X Yoga」,最多說「有 X Yoga 的某些特徵」。\n'
       + '⑨ 提到西占上升/MC = 上方西洋欄位的值。\n'
       + '⑩ 提到土星/木星/外行星行運到哪宮 = 上方「當前外行星行運」欄位,不在清單 = 不能斷言有。\n'
       + '⑪ 提到名字是「幫」還是「拖」 = 上方「五格vs八字喜用」欄位,不能憑感覺。\n'
       + '⑫ 提到梅花本卦/變卦卦名 = 上方「本卦」「變卦」欄位,禁止自創「天雷無妄」等不在清單的卦名。\n'
       + '⑬ 提到梅花體卦/用卦 = 上方「體卦」「用卦」欄位,體永遠是問卦人本身,禁止把對方當體。\n'
       + '⑭ 講梅花應期月份 = 上方「三法交集應期」欄位,禁止自套公式重算。信心低時允許說「粗略範圍」。\n'
       + '⑮ 上方沒列的細節(十神、地支互動、宮位飛化、神煞、細部大運走勢、每顆行星度數等)才允許引用下方完整 dims 資料。\n'
       + '⑯ 寫完自檢: 每一句關於大運/日主/配偶宮/主星/Dasha/Nakshatra/行運/Yoga/梅花卦名/體用/應期的話,是否都對齊上方錨點? 否→重寫。\n'
       + '═══════════════════════════════════════════════\n\n';
}

// v47：用戶個人 override——每筆解讀綁幾次免費追問
async function getUserFuPerResult(env, userKey, globalDefault) {
  var g = (typeof globalDefault === 'number') ? globalDefault : DEFAULT_FU_PER_RESULT;
  if (!env.RATE_KV) return g;
  try {
    const v = await env.RATE_KV.get(`fu_per_result:${userKey}`);
    if (v !== null) {
      var n = parseInt(v);
      if (!isNaN(n) && n >= 0) return n;
    }
  } catch(_) {}
  return g;
}

// v60-hotfix2：三工具獨立免費上限。
//   mode = '7d' | 'tarot' | 'ootk'（不傳則為統一上限向後相容）
//   讀取順序：工具專屬 KV → 舊統一 free_limit KV → FREE_PER_MODE_LIMIT 預設值
//   這樣既支援 admin 分工具設定，也向後相容舊用戶只有 free_limit 的狀況。
async function getUserFreeLimit(env, userKey, mode) {
  if (!env.RATE_KV) return FREE_PER_MODE_LIMIT;
  try {
    // v60-hotfix2：先讀工具專屬 KV（若傳 mode）
    if (mode === '7d' || mode === 'tarot' || mode === 'ootk') {
      const toolKey = `free_${mode}_limit:${userKey}`;
      const toolCustom = await env.RATE_KV.get(toolKey);
      if (toolCustom !== null) {
        var _tn = parseInt(toolCustom);
        if (!isNaN(_tn) && _tn >= 0) return _tn;
      }
    }
    // fallback 舊統一 KV（向後相容）
    const custom = await env.RATE_KV.get(`free_limit:${userKey}`);
    // v47：0 是合法值（admin 設 0 表示停用該用戶免費額度），不能被 || 誤吞回預設
    if (custom !== null) {
      var _n = parseInt(custom);
      if (!isNaN(_n) && _n >= 0) return _n;
    }
  } catch(_) {}
  return FREE_PER_MODE_LIMIT;
}
// v52：讀取用戶會員 tier
//   返回 'premium' | 'standard' | null（null = 非會員）
//   兼容舊資料：sub:{userKey} 若沒有 tier 欄位，預設 standard
async function getUserSubTier(env, userKey) {
  if (!env.RATE_KV) return null;
  try {
    const raw = await env.RATE_KV.get(`sub:${userKey}`);
    if (!raw) return null;
    const obj = JSON.parse(raw);
    if (obj && obj.expiresAt && obj.expiresAt < Date.now()) return null; // 已過期
    if (obj && obj.tier === 'premium') return 'premium';
    return 'standard'; // 舊資料 / 預設
  } catch(_) { return null; }
}

async function getUserSubDailyLimit(env, userKey) {
  if (!env.RATE_KV) return SUB_TAROT_DAILY_STANDARD;
  try {
    // 優先讀 admin 針對個別用戶的 override
    const v = await env.RATE_KV.get(`sub_daily_limit:${userKey}`);
    if (v !== null) {
      var _n = parseInt(v);
      if (!isNaN(_n) && _n >= 0) return _n;
    }
    // 沒 override → 看 tier
    const tier = await getUserSubTier(env, userKey);
    if (tier === 'premium') return SUB_TAROT_DAILY_PREMIUM;
    return SUB_TAROT_DAILY_STANDARD;
  } catch(_) {}
  return SUB_TAROT_DAILY_STANDARD;
}
async function getUserD7Limit(env, userKey) {
  if (!env.RATE_KV) return SUB_7D_MONTHLY_STANDARD;
  try {
    const v = await env.RATE_KV.get(`7d_limit:${userKey}`);
    if (v !== null) {
      var _n = parseInt(v);
      if (!isNaN(_n) && _n >= 0) return _n;
    }
    const tier = await getUserSubTier(env, userKey);
    if (tier === 'premium') return SUB_7D_MONTHLY_PREMIUM;
    return SUB_7D_MONTHLY_STANDARD;
  } catch(_) {}
  return SUB_7D_MONTHLY_STANDARD;
}
async function getUserOpusLimit(env, userKey) {
  // v52：Opus 免費次數只給高級會員（OPUS_MONTHLY_FREE=1）。標準會員 = 0（要 Opus 就自己加購或升級）
  if (!env.RATE_KV) return OPUS_MONTHLY_FREE_STANDARD;
  try {
    const v = await env.RATE_KV.get(`opus_limit:${userKey}`);
    if (v !== null) {
      var _n = parseInt(v);
      if (!isNaN(_n) && _n >= 0) return _n;
    }
    const tier = await getUserSubTier(env, userKey);
    if (tier === 'premium') return OPUS_MONTHLY_FREE;
    return OPUS_MONTHLY_FREE_STANDARD;
  } catch(_) {}
  return OPUS_MONTHLY_FREE_STANDARD;
}

// ═══════════════════════════════════════════════════════════════
// ★ v48：靜月記事本 KV 讀寫
// ═══════════════════════════════════════════════════════════════
// - KV key: memory:{userKey}
// - 格式：JSON，陣列，每條 { t: timestamp, mode: '7d|tarot|ootk', topic, timeWindow, insight, systems }
// - 保留策略：最多 30 條，超過 FIFO 淘汰
// - TTL：365 天（每次 append 都會續期）
// - 跨模型上限：依呼叫方的 model 類型決定注入多少條（Opus 4.7=全給，Sonnet/Haiku=截斷最近 10 條）
const MEMORY_MAX_ENTRIES = 30;
const MEMORY_TTL_SECONDS = 365 * 86400;

async function getUserMemoryNotes(env, userKey) {
  if (!env.RATE_KV || !userKey) return [];
  try {
    const raw = await env.RATE_KV.get(`memory:${userKey}`);
    if (!raw) return [];
    const arr = JSON.parse(raw);
    return Array.isArray(arr) ? arr : [];
  } catch (_) { return []; }
}

async function appendUserMemoryNotes(env, userKey, mode, newNotes) {
  if (!env.RATE_KV || !userKey) return;
  if (!Array.isArray(newNotes) || newNotes.length === 0) return;
  try {
    const existing = await getUserMemoryNotes(env, userKey);
    const now = Date.now();
    const cleaned = newNotes
      .filter(n => n && typeof n === 'object' && n.insight)
      .slice(0, 5)  // AI 最多寫 5 條
      .map(n => ({
        t: now,
        mode: String(mode || '').slice(0, 16),
        topic: String(n.topic || '整體').slice(0, 16),
        timeWindow: String(n.timeWindow || '無時限').slice(0, 32),
        insight: String(n.insight || '').slice(0, 120),
        systems: Array.isArray(n.systems) ? n.systems.slice(0, 3).map(s => String(s).slice(0, 8)) : []
      }));
    const merged = cleaned.concat(existing).slice(0, MEMORY_MAX_ENTRIES); // 新的在前，FIFO 淘汰舊的
    await env.RATE_KV.put(`memory:${userKey}`, JSON.stringify(merged), { expirationTtl: MEMORY_TTL_SECONDS });
  } catch (_) {}
}

// ★ v48：格式化記憶為 user message 注入塊
// - modelTier: 'opus4_7' | 'opus4_6' | 'sonnet' | 'haiku'
// - 跨模型截斷：Opus 4.7 全給（1M context），其他保留最近 10 條
function formatMemoryForPrompt(notes, modelTier) {
  if (!Array.isArray(notes) || notes.length === 0) return '';
  let maxEntries = 10;
  if (modelTier === 'opus4_7') maxEntries = 30;          // Opus 4.7 有 1M context，全給
  else if (modelTier === 'opus4_6') maxEntries = 15;     // Opus 4.6 也是 200k，但推理強
  else maxEntries = 10;                                   // Sonnet/Haiku 保守
  const used = notes.slice(0, maxEntries);
  const lines = used.map(n => {
    const d = new Date(n.t || Date.now());
    const ymd = d.getFullYear() + '/' + String(d.getMonth() + 1).padStart(2, '0') + '/' + String(d.getDate()).padStart(2, '0');
    const sys = (n.systems && n.systems.length) ? `（${n.systems.join('+')}）` : '';
    return `- [${ymd}｜${n.topic}｜${n.timeWindow}] ${n.insight}${sys}`;
  });
  return '═══ 靜月記事本（上次解讀的記憶，最新在上）═══\n' +
    `共 ${notes.length} 條，此次給你看 ${used.length} 條：\n` +
    lines.join('\n') +
    '\n═══ 記事本結束 ═══\n\n使用原則：\n①只在「本次數據跟上次判斷應驗/反轉/相關」時引用，不要每次都提。\n②本次的 memoryNotes 是新增判斷，不要重複記事本裡已有的。\n③如果記事本有「X 月發生 Y」而本次剛好是 X 月前後——主分析要提一下「上次我提過」，這是記憶黏著的核心。\n\n';
}

// ★ v48：根據 modelId 判斷 tier，用於記憶截斷策略
function _detectModelTier(modelId) {
  const m = String(modelId || '').toLowerCase();
  if (m.includes('opus-4-7')) return 'opus4_7';
  if (m.includes('opus-4-6') || m.includes('opus')) return 'opus4_6';
  if (m.includes('haiku')) return 'haiku';
  return 'sonnet';
}

// ★ v48：載入使用者記憶並格式化為 prefix（呼叫 AI 前用）
// - 只對「有 email 的登入用戶」啟用，訪客/未登入不注入記憶
// - 失敗不拋錯，回傳空字串（記憶失敗 ≠ 讀盤失敗）
async function _loadMemoryPrefix(env, userKey, sessionUser, modelId) {
  try {
    if (!env || !env.RATE_KV) return '';
    if (!sessionUser || !sessionUser.email) return ''; // 未登入不吃記憶
    const notes = await getUserMemoryNotes(env, userKey);
    if (!notes.length) return '';
    return formatMemoryForPrompt(notes, _detectModelTier(modelId));
  } catch (_) { return ''; }
}

// ★ v48：從 AI 結果 result.memoryNotes 提取後寫回 KV（呼叫 AI 後用）
// - 只對登入用戶寫入；追問路徑不呼叫這個
// - 失敗不拋錯（寫記憶失敗 ≠ 返回失敗給用戶）
async function _saveMemoryNotes(env, userKey, sessionUser, mode, result) {
  try {
    if (!env || !env.RATE_KV) return;
    if (!sessionUser || !sessionUser.email) return;
    if (!result || !Array.isArray(result.memoryNotes)) return;
    await appendUserMemoryNotes(env, userKey, mode, result.memoryNotes);
  } catch (_) {}
}

// ★ 取得金流憑證（從 env 讀取，fallback 到舊常數以防部署過渡期）
function _getECPayCreds(env) {
  return {
    merchantId: (env && env.ECPAY_MERCHANT_ID) || '3493341',
    hashKey:    (env && env.ECPAY_HASH_KEY)    || '',
    hashIV:     (env && env.ECPAY_HASH_IV)     || ''
  };
}

function generateTradeNo() {
  // 綠界要求: 英數字 20 碼內，不可重複
  const now = Date.now().toString(36).toUpperCase();
  const rand = Math.random().toString(36).substring(2, 8).toUpperCase();
  return ('JY' + now + rand).substring(0, 20);
}

// ★ v46：首輪解讀完成後發給前端的 resultId（追問用來換 1 次免費追問）
function generateResultId() {
  const rand1 = Math.random().toString(36).substring(2, 10);
  // ★ Bug #2 fix: substring 不接受負數參數（會被當 0），要拿尾 4 字元應該用 slice(-4)
  //   舊版回傳整個字串，rand2 變超長，最終 substring(0,16) 截掉
  //   結果還是能用，但 rand2 失去取尾 4 字元的意圖（每秒只有開頭那段在變）
  const rand2 = Date.now().toString(36).slice(-4);
  return ('r_' + rand1 + rand2).substring(0, 16);
}

// ★ v46：算到台灣時區今日結束（23:59:59）還剩幾秒，用於 fu_free TTL
//    這樣當天沒用的免費追問資格過了午夜就自動過期
function getSecondsUntilTaipeiEndOfDay() {
  const nowMs = Date.now();
  const tpNow = new Date(nowMs + 8 * 3600000);
  const endOfDayUtcMs = Date.UTC(
    tpNow.getUTCFullYear(),
    tpNow.getUTCMonth(),
    tpNow.getUTCDate(),
    23, 59, 59
  ) - 8 * 3600000;
  const secs = Math.ceil((endOfDayUtcMs - nowMs) / 1000);
  return secs > 60 ? secs : 60; // 最少 60 秒（避免剛好跨日失效）
}

function formatECPayDate(d) {
  const pad = (n) => String(n).padStart(2, '0');
  return `${d.getFullYear()}/${pad(d.getMonth()+1)}/${pad(d.getDate())} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

async function generateCheckMacValue(params, creds) {
  // 1. 按參數名稱排序
  const sorted = Object.keys(params).sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));
  // 2. 組成 key=value& 字串
  let raw = `HashKey=${creds.hashKey}`;
  for (const key of sorted) {
    raw += `&${key}=${params[key]}`;
  }
  raw += `&HashIV=${creds.hashIV}`;
  // 3. URL encode (小寫)
  raw = encodeURIComponent(raw).toLowerCase();
  // 4. 特殊字元還原 (綠界規格)
  raw = raw.replace(/%2d/g, '-').replace(/%5f/g, '_').replace(/%2e/g, '.').replace(/%21/g, '!').replace(/%2a/g, '*').replace(/%28/g, '(').replace(/%29/g, ')').replace(/%20/g, '+');
  // 5. SHA256 → 大寫
  const hash = await sha256Hex(raw);
  return hash.toUpperCase();
}

async function sha256Hex(str) {
  const data = new TextEncoder().encode(str);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  return Array.from(new Uint8Array(hashBuffer)).map(b => b.toString(16).padStart(2, '0')).join('');
}

// 產生綠界付款表單 HTML（前端會收到這個 HTML 然後自動 submit）
async function buildECPayFormHTML(tradeNo, workerBaseUrl, amount, itemName, env, choosePayment) {
  const creds = _getECPayCreds(env);
  const now = new Date(Date.now() + 8 * 3600000); // UTC+8
  const params = {
    MerchantID: creds.merchantId,
    MerchantTradeNo: tradeNo,
    MerchantTradeDate: formatECPayDate(now),
    PaymentType: 'aio',
    TotalAmount: String(amount),
    TradeDesc: encodeURIComponent('靜月之光AI深度解讀'),
    ItemName: itemName || 'AI深度命理解讀x1',
    ReturnURL: `${workerBaseUrl}/ecpay-notify`,
    // v60-hotfix7-e：OrderResultURL 不能直接指向 GitHub Pages（靜態主機拒收綠界 POST → HTTP 405）
    //   改指向 worker 的 /ecpay-return，worker 接到 POST 後用 302 redirect 把用戶以 GET 帶回 jingyue.uk?paid=xxx
    //   這樣用戶體驗無縫：付完自動回到原網站，前端 _checkPaymentReturn 讀 ?paid 參數解鎖
    OrderResultURL: `${workerBaseUrl}/ecpay-return?tradeNo=${tradeNo}`,
    ChoosePayment: choosePayment || 'ALL',
    EncryptType: '1',
    ClientBackURL: 'https://jingyue.uk',
    NeedExtraPaidInfo: 'N',
  };
  params.CheckMacValue = await generateCheckMacValue(params, creds);

  // 產生自動提交的 HTML form
  let formFields = '';
  for (const [key, val] of Object.entries(params)) {
    formFields += `<input type="hidden" name="${key}" value="${val}">`;
  }
  return `<!DOCTYPE html><html><head><meta charset="utf-8"><title>前往付款...</title></head><body>
<form id="ecpay" method="POST" action="${ECPAY_PAYMENT_URL}">${formFields}</form>
<script>document.getElementById('ecpay').submit();</script>
</body></html>`;
}

// 解析 URL encoded form body（綠界回傳用）
function parseFormBody(text) {
  const params = {};
  for (const pair of text.split('&')) {
    const [k, ...v] = pair.split('=');
    if (k) params[decodeURIComponent(k)] = decodeURIComponent(v.join('='));
  }
  return params;
}


// ═══════════════════════════════════════════════════════════════
// Google OAuth 工具
// ═══════════════════════════════════════════════════════════════

const GOOGLE_AUTH_URL = 'https://accounts.google.com/o/oauth2/v2/auth';
const GOOGLE_TOKEN_URL = 'https://oauth2.googleapis.com/token';
const GOOGLE_USERINFO_URL = 'https://www.googleapis.com/oauth2/v2/userinfo';
const OAUTH_REDIRECT_PATH = '/auth/callback';
const SESSION_TTL = 86400 * 30; // 30 天

function generateSessionToken() {
  const arr = new Uint8Array(32);
  crypto.getRandomValues(arr);
  return Array.from(arr, b => b.toString(16).padStart(2, '0')).join('');
}

async function getUserFromSession(body, env) {
  // 從 body.session_token 或 header Authorization 取 session token
  const token = safeString(body?.session_token);
  if (!token || !env.RATE_KV) return null;
  try {
    const data = await env.RATE_KV.get(`session:${token}`);
    if (!data) return null;
    return JSON.parse(data);
  } catch (_e) { return null; }
}

// 取得使用者識別 key（登入用 email，未登入用 IP）
// v48 bug 修：email 強制 lowercase + trim
// v62 修補：Gmail 別名正規化——防止 user.name+anything@gmail.com 與 username@gmail.com 被當成不同帳號
//   Gmail 規則：①local part 的 . 全部移除 ②+ 後面的別名移除 ③僅對 @gmail.com / @googlemail.com 生效
//   Google 把這些都送同一個信箱，但 OAuth 給的 email 字串可能不同（按用戶填寫保留原貌）
//   未正規化會被攻擊者用來繞過免費限額（同一個 Gmail 信箱當無數個 email 用）
function _normalizeGmail(email) {
  if (!email) return email;
  var atIdx = email.lastIndexOf('@');
  if (atIdx < 0) return email;
  var local = email.slice(0, atIdx);
  var domain = email.slice(atIdx + 1);
  if (domain === 'gmail.com' || domain === 'googlemail.com') {
    var plusIdx = local.indexOf('+');
    if (plusIdx >= 0) local = local.slice(0, plusIdx);
    local = local.replace(/\./g, '');
    // 全部統一為 gmail.com（googlemail.com 是 Gmail 的舊域名別名）
    return local + '@gmail.com';
  }
  return email;
}
// v62 安全補丁：統一從 email 推導 userKey 的 helper
//   所有「直接拼 u:${email}」的端點都應改用此函式，避免不同端點對同一個 email 推出不同 key
//   例如 admin grant 用了 j.o.h.n@gmail.com 但用戶登入後 getUserKey 拿到 u:john@gmail.com → 對不到 sub 資料
//   helper 強制 lowercase + trim + Gmail 別名正規化，與 getUserKey 完全一致
function _emailToUserKey(email) {
  if (!email) return null;
  var _e = String(email).trim().toLowerCase();
  if (!_e) return null;
  _e = _normalizeGmail(_e);
  return 'u:' + _e;
}
function getUserKey(sessionUser, ip) {
  if (!sessionUser) return ip;
  var _e = String(sessionUser.email || '').trim().toLowerCase();
  if (_e) _e = _normalizeGmail(_e);
  return _e ? `u:${_e}` : ip;
}

// v60-hotfix6 Bug E1：驗證 paid_token 的擁有者
//   向後相容：paid_owner 不存在時返 true（舊 token 放行）
//   paid_owner 存在時比對 userKey，不符返 false
async function verifyPaidTokenOwner(env, tradeNo, userKey) {
  if (!env.RATE_KV || !tradeNo) return true; // 無 KV 則不阻擋
  try {
    const owner = await env.RATE_KV.get(`paid_owner:${tradeNo}`);
    if (owner === null) return true; // 舊 token 沒綁 owner → 放行（向後相容）
    return owner === userKey;
  } catch(_) { return true; } // KV 讀取失敗不阻擋（寧願漏也不誤殺）
}

// ═══════════════════════════════════════════════════════════════
// v64.C:單次購買「配額制」(取代 paid_token 一次性 token 機制)
// ───────────────────────────────────────────────────────────────
// 七池(每池都有「已用/上限」):
//   PAID_QUOTA_KEYS = ['7d_std','7d_opus','tarot_std','tarot_opus','ootk_std','ootk_opus','fu']
// KV 結構(用單一 JSON 存,降 KV 操作數):
//   paid_quota:{userKey} = '{"7d_std":{"u":0,"l":1},"7d_opus":{"u":0,"l":0},...}'
//   u = used, l = limit
// 購買 → 對應 .l +=1
// 使用 → precheck u < l 才放行 → 成功後 .u +=1
// 達上限 → 擋住 → 前端彈付費牆
// ═══════════════════════════════════════════════════════════════
const PAID_QUOTA_KEYS = ['7d_std', '7d_opus', 'tarot_std', 'tarot_opus', 'ootk_std', 'ootk_opus', 'fu'];

// 把 (mode, depth) → 配額 key
//   mode: 'full'|'tarot_only'|'ootk' / depth: 'sonnet'|'opus' / type: 'fu' (追問)
function _resolvePaidQuotaKey(mode, depth) {
  if (depth === 'fu') return 'fu';
  const tool = (mode === 'tarot_only' || mode === 'tarot') ? 'tarot'
             : (mode === 'ootk') ? 'ootk'
             : '7d';
  const dep = (depth === 'opus') ? 'opus' : 'std';
  return `${tool}_${dep}`;
}

// 讀某用戶完整配額 obj
async function getAllPaidQuotas(env, userKey) {
  if (!env.RATE_KV || !userKey) return {};
  try {
    const raw = await env.RATE_KV.get(`paid_quota:${userKey}`);
    if (!raw) return {};
    const obj = JSON.parse(raw);
    return obj || {};
  } catch(_) { return {}; }
}

// 讀單一配額 {used, limit, remaining}
async function getPaidQuota(env, userKey, key) {
  if (!env.RATE_KV || !userKey || !key) return { used: 0, limit: 0, remaining: 0 };
  try {
    const all = await getAllPaidQuotas(env, userKey);
    const q = all[key] || { u: 0, l: 0 };
    const used = parseInt(q.u || 0);
    const limit = parseInt(q.l || 0);
    return { used, limit, remaining: Math.max(0, limit - used) };
  } catch(_) { return { used: 0, limit: 0, remaining: 0 }; }
}

// 統一更新函式,確保多筆改動只寫一次 KV(降低 race + KV 寫次數)
async function _updatePaidQuota(env, userKey, key, deltaUsed, deltaLimit) {
  if (!env.RATE_KV || !userKey || !key) return false;
  try {
    const all = await getAllPaidQuotas(env, userKey);
    const cur = all[key] || { u: 0, l: 0 };
    const newU = Math.max(0, parseInt(cur.u || 0) + (deltaUsed || 0));
    const newL = Math.max(0, parseInt(cur.l || 0) + (deltaLimit || 0));
    all[key] = { u: newU, l: newL };
    await env.RATE_KV.put(`paid_quota:${userKey}`, JSON.stringify(all));
    return true;
  } catch(e) { return false; }
}

// 上限 +N(購買後呼叫)
async function addPaidQuota(env, userKey, key, n) {
  return _updatePaidQuota(env, userKey, key, 0, Math.max(1, parseInt(n) || 1));
}

// 已用 +1(成功用完一次後呼叫)
async function consumePaidQuota(env, userKey, key) {
  return _updatePaidQuota(env, userKey, key, 1, 0);
}

// admin 直接覆寫某條配額(used 或 limit)
async function setPaidQuotaField(env, userKey, key, field, value) {
  if (!env.RATE_KV || !userKey || !key) return false;
  if (field !== 'u' && field !== 'l') return false;
  try {
    const all = await getAllPaidQuotas(env, userKey);
    const cur = all[key] || { u: 0, l: 0 };
    cur[field] = Math.max(0, parseInt(value) || 0);
    // 確保 used <= limit(避免顯示 1/0 之類詭異值)
    if (field === 'l' && cur.u > cur.l) cur.u = cur.l;
    all[key] = cur;
    await env.RATE_KV.put(`paid_quota:${userKey}`, JSON.stringify(all));
    return true;
  } catch(e) { return false; }
}

// 舊 paid_token lazy 遷移
//   若用戶有合法的 paid_token(屬於 mode/depth 對應類型) → 換成 paid_limit +=1 並燒掉
//   保護老客戶已付款資產不消失
//   回傳 true 表示遷移成功(用戶現在可以走配額制)
async function migrateLegacyPaidToken(env, userKey, paidTradeNo, expectMode, expectDepth) {
  if (!env.RATE_KV || !userKey || !paidTradeNo) return false;
  try {
    const tokenVal = await env.RATE_KV.get(`paid_token:${paidTradeNo}`);
    if (!tokenVal) return false;
    // owner 驗證
    const owner = await env.RATE_KV.get(`paid_owner:${paidTradeNo}`);
    if (owner !== null && owner !== userKey) return false;
    // 確認 type 跟期望相符
    let actualDepth;
    if (tokenVal === 'opus') actualDepth = 'opus';
    else if (tokenVal === 'fu') actualDepth = 'fu';
    else actualDepth = 'std';
    if (actualDepth !== expectDepth) return false;
    // 算配額 key
    const qkey = _resolvePaidQuotaKey(expectMode, actualDepth);
    // 上限 +1,然後燒掉舊 token
    await addPaidQuota(env, userKey, qkey, 1);
    await env.RATE_KV.delete(`paid_token:${paidTradeNo}`);
    await env.RATE_KV.delete(`single_use:${paidTradeNo}`);
    await env.RATE_KV.delete(`paid_owner:${paidTradeNo}`);
    return true;
  } catch(e) { return false; }
}

// ═══════════════════════════════════════════════════════════════
// 歷史脈絡注入(讓 AI 看見用戶過去 fb,實現「越用越深」)
//
// 規則:
// 1. 只有登入用戶才有歷史(匿名 IP 用戶不啟用)
// 2. 抓最近 30 天最多 5 筆 fb,優先「對得上」(good) 再次「太籠統」(vague)
// 3. 「對不上」(bad) 也要,但只看 reasons(用戶具體不滿意什麼)
// 4. 結果只附最關鍵摘要,不夾完整解讀內容(避免污染當下 prompt)
// 5. 失敗 silent,不影響主流程
// ═══════════════════════════════════════════════════════════════
async function getUserHistoryContext(env, userKey) {
  if (!env.RATE_KV || !userKey || !userKey.startsWith('u:')) return '';
  try {
    // KV list 撈這個用戶過去的 fb(prefix 'fb:' + 時間戳，無法直接精準 list per-user，
    // 改成從用戶歷史索引拉，索引在 fb 寫入時同步建立)
    // 索引 key: ufb:{userKey}:{ts}  → 值是 fb key
    const idxList = await env.RATE_KV.list({ prefix: 'ufb:' + userKey + ':', limit: 20 });
    if (!idxList.keys || idxList.keys.length === 0) return '';

    // 取最新 5 筆(KV list 預設按 key 升序,key 含 ts → 取尾 5)
    const sortedKeys = idxList.keys.sort((a, b) => b.name.localeCompare(a.name)).slice(0, 5);
    const fbs = await Promise.all(sortedKeys.map(async (k) => {
      try {
        const fbKeyName = await env.RATE_KV.get(k.name);
        if (!fbKeyName) return null;
        const raw = await env.RATE_KV.get(fbKeyName);
        if (!raw) return null;
        return JSON.parse(raw);
      } catch(_) { return null; }
    }));

    const validFbs = fbs.filter(fb => fb && fb.rating);
    if (validFbs.length === 0) return '';

    // 統計用戶偏好特徵
    const ratingCount = { good: 0, vague: 0, bad: 0 };
    const negReasons = []; // 用戶常見不滿意的點
    const posReasons = []; // 用戶常見滿意的點
    const recentTopics = []; // 用戶最近關心的領域

    validFbs.forEach(fb => {
      ratingCount[fb.rating] = (ratingCount[fb.rating] || 0) + 1;
      if (fb.type) recentTopics.push(fb.type);
      if (fb.rating === 'good' && fb.reasons) posReasons.push(fb.reasons);
      if ((fb.rating === 'bad' || fb.rating === 'vague') && fb.reasons) negReasons.push(fb.reasons);
    });

    // 組成簡潔脈絡(夾在 user message 開頭，不進 system 避免 cache 失效)
    const lines = [];
    lines.push('[此用戶歷史脈絡(僅供 AI 調整解讀深度,不要直接複述給用戶)]');
    lines.push('過往回饋:對得上 ' + (ratingCount.good||0) + ' 次 / 太籠統 ' + (ratingCount.vague||0) + ' 次 / 對不上 ' + (ratingCount.bad||0) + ' 次');

    if (negReasons.length > 0) {
      // 取頻繁出現的 reasons keyword
      const reasonStr = negReasons.join('、').substring(0, 100);
      lines.push('過去不滿意:' + reasonStr);
      lines.push('→ 本次解讀請避開這些問題:更具體、有個人化判斷、避免空泛抽象。');
    }

    if (posReasons.length > 0) {
      const reasonStr = posReasons.join('、').substring(0, 100);
      lines.push('過去滿意:' + reasonStr);
      lines.push('→ 本次保持這個方向。');
    }

    if (recentTopics.length > 0) {
      const topicSet = Array.from(new Set(recentTopics)).slice(0, 3);
      lines.push('近期關心領域:' + topicSet.join('、'));
    }

    lines.push('[歷史脈絡結束]');
    lines.push(''); // 空行分隔

    return lines.join('\n');
  } catch(_) {
    return ''; // 失敗 silent,不影響主流程
  }
}

// ═══════════════════════════════════════════════════════════════
// callAI — Anthropic streaming API（防止 Cloudflare Worker timeout）
// 使用 stream:true 讓 Anthropic 即時回傳 SSE，Worker 邊收邊組裝
// ═══════════════════════════════════════════════════════════════
async function callAI(env, system, userMessage, maxTokens, temp, model, keepAlive, options) {
  const useModel = model || 'claude-sonnet-4-6';
  const maxRetries = 2;
  // ★ v47：options = { effort: 'max'|'xhigh'|'high'|'medium'|'low', enableThinking: true|false }
  // 只有 opus-4-7 會套用，其他模型忽略這些選項
  // v49: 'max' 為 2026/4 官方新選項，intelligence-demanding tasks 最高等級（命理深度判讀屬此類）
  // ★ v49：options 新增 haikuThinking = { enabled, budgetTokens, isFollowup, includeFollowup }
  //         由呼叫點從 admin KV config 讀取後傳入（避免 callAI 重複讀 KV）
  // ★ v53：options 新增 opus46Effort / sonnet46Effort（從 admin KV config 讀取）
  //         讓 4 個模型的 effort/thinking 全部由 admin 即時切換，不需重新部署
  // ★ 新增：options.userKey → 啟用「越用越深」的歷史脈絡注入
  //   把用戶過去 fb 摘要 prepend 到 user message(不放 system,避免破壞 prompt cache)
  const _opts = options || {};
  const _isOpus47 = useModel.includes('opus-4-7');
  const _isOpus46 = useModel.includes('opus-4-6');
  const _isSonnet46 = useModel.includes('sonnet-4-6');
  const _isHaiku45 = useModel.includes('haiku-4-5');

  // ★ 「越用越深」歷史脈絡注入(限第一次 retry,失敗不重試以省成本)
  // ★ v63.8 Bug fix:userMessage 可能是陣列(buildMessageWithPhotos 在有照片時回陣列)
  //   舊版直接用 + 串接,陣列被 toString 變 "[object Object],[object Object]"
  //   修法:檢查型別,陣列就把 history 插在第一個 text block 前面
  let _userMsgWithHistory = userMessage;
  if (_opts.userKey && typeof _opts.userKey === 'string' && _opts.userKey.startsWith('u:')) {
    try {
      const _history = await getUserHistoryContext(env, _opts.userKey);
      if (_history) {
        if (Array.isArray(userMessage)) {
          // 陣列(有照片):把 history 包成 text block 插在最前面
          //   照片 + 文字結構保留,只在最前面多加一個 text block
          _userMsgWithHistory = [{ type: 'text', text: _history }].concat(userMessage);
        } else {
          // 字串(沒照片):直接 + 串接
          _userMsgWithHistory = _history + '\n' + userMessage;
        }
      }
    } catch(_hE) { /* silent */ }
  }
  // 從這裡起所有 userMessage 引用都改用 _userMsgWithHistory
  const _finalUserMessage = _userMsgWithHistory;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      // ★ v37 S2：Prompt caching — system prompt 包成 cache_control block
      // ★ v62c：TTL 從預設 5min 升到 1h（Anthropic 官方 2025-11 支援）
      //          命理場景用戶常連續問追問，5min 會 miss cache；1h 命中率更高
      //          cache write 成本從 1.25x 升到 2x，但 cache hit 省 90%
      //          只要 1h 內有 >2 次請求就回本
      // ★ v62f-fix-4：cache TTL 動態化——由呼叫點傳入（admin 可切 5m/1h）
      //   _opts.cacheTTL = '5m'（預設低流量省錢）| '1h'（高流量同 system prompt 重用）
      const _cacheTTL = (_opts.cacheTTL === '1h') ? '1h' : '5m';
      const _cacheControl = (_cacheTTL === '1h')
        ? { type: 'ephemeral', ttl: '1h' }
        : { type: 'ephemeral' }; // 5m 是 Anthropic 預設，不用寫 ttl
      const systemBlocks = [
        { type: 'text', text: system, cache_control: _cacheControl }
      ];
      // ★ v43：Haiku 不送舊版 beta header（改用新版自動 caching），避免衝突
      // ★ v62c：Haiku 以外都送 extended-cache-ttl beta header（啟用 1h TTL）
      // ★ v62f-fix-4：只在 1h TTL 時送 extended-cache-ttl beta header
      const _headers = {
        'Content-Type': 'application/json',
        'x-api-key': env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01'
      };
      if (!useModel.includes('haiku')) {
        // 1h TTL 才需要 extended-cache-ttl-2025-04-11 beta
        _headers['anthropic-beta'] = (_cacheTTL === '1h')
          ? 'prompt-caching-2024-07-31,extended-cache-ttl-2025-04-11'
          : 'prompt-caching-2024-07-31';
      }
      // ★ v44c：claude-opus-4-7 不支援 temperature / top_p / top_k，需省略
      // ★ v47：Opus 4.7 啟用 adaptive thinking + effort（官方建議 intelligence-sensitive 用 high+ 以上）
      // ★ v53：Opus 4.6 / Sonnet 4.6 也升級到 adaptive thinking + effort（官方文件 2026/04）
      //         budget_tokens 在 4.6 已 deprecated，未來會移除
      const _body = {
        model: useModel,
        max_tokens: maxTokens,
        system: systemBlocks,
        stream: true,
        messages: [{ role: 'user', content: _finalUserMessage }]
      };
      // ═══════════════════════════════════════════════════════════════════
      // ★ v62e：Assistant Prefill —— 【v62f-hotfix：已停用】
      //   原因：官方 2026-02 文件確認，Claude 4.5/4.6/4.7 全系列都不支援 prefill
      //   - Opus 4.7 ❌ 400 error
      //   - Opus 4.6 ❌ 400 error
      //   - Sonnet 4.6 ❌ 400 error（我們原本以為支援，實測證實不支援）
      //   - Haiku 4.5 ❌ 400 error（GitHub issue 明確記錄）
      //   error message："This model does not support assistant message prefill.
      //                   The conversation must end with a user message."
      //   官方建議改用：output_config.format / structured outputs / system prompt 指令
      //   實測印證：2026-04-24 用戶回報 Sonnet 4.6 開啟 prefill 後 400 error
      //   處理：不管 admin 設什麼，都直接 bypass prefill 邏輯
      //   保留 admin UI 卡片但加上「已停用」標記，避免誤操作
      // ═══════════════════════════════════════════════════════════════════
      // 原本的 prefill 注入邏輯已 disable（保留註解作為歷史記錄）：
      // if (_opts.prefillEnabled === true && _opts.prefillText && !_isOpus47 && !_isOpus46) {
      //   _body.messages.push({ role: 'assistant', content: _opts.prefillText });
      // }
      // ═══════════════════════════════════════════════════════════════════
      // ═══════════════════════════════════════════════════════════════════
      // ★ v62d：Advisor Tool 注入（beta）
      //   官方：https://platform.claude.com/docs/en/agents-and-tools/tool-use/advisor-tool
      //   原理：executor（Sonnet/Haiku/Opus 4.6）遇到複雜判斷時呼叫 advisor（Opus 4.7）
      //         advisor 看完整 transcript 給出策略建議，executor 繼續執行
      //         全部在單一 API 請求內完成，streaming 只暫停、不中斷
      //   命理用途：會員線 Sonnet 4.6 執行時遇到「這盤面訊號打架」求助 Opus 4.7
      //            → 準確度接近付費線，成本遠低於全換 Opus
      //   模型相容性：advisor 必須 ≥ executor（見官方 Model compatibility 表）
      //              - Haiku/Sonnet 4.6/Opus 4.6 的 executor → advisor 用 Opus 4.7
      //              - Opus 4.7 自己當 executor 時不需要 advisor（已是最強）
      //   由呼叫點決定是否啟用（_opts.advisorEnabled）
      // ═══════════════════════════════════════════════════════════════════
      if (_opts.advisorEnabled === true && _opts.advisorModel && !_isOpus47) {
        // Opus 4.7 已是最強，不需要 advisor（Opus 4.7 當 executor 時 advisor 只能等於自己）
        // 只對 Haiku/Sonnet 4.6/Opus 4.6 注入 advisor
        const _advisorTool = {
          type: 'advisor_20260301',
          name: 'advisor',
          model: _opts.advisorModel,
          max_uses: _opts.advisorMaxUses || 2
        };
        // 若啟用 advisor-side caching，加上 caching object
        if (_opts.advisorCaching === true) {
          _advisorTool.caching = { type: 'ephemeral', ttl: '1h' };
        }
        _body.tools = [_advisorTool];
        // 疊加 beta header（不覆蓋 prompt-caching / extended-cache-ttl）
        const _existingBeta = _headers['anthropic-beta'] || '';
        _headers['anthropic-beta'] = _existingBeta
          ? _existingBeta + ',advisor-tool-2026-03-01'
          : 'advisor-tool-2026-03-01';
      }
      // Opus 4.7 不支援 temperature；其他模型保留
      if (!_isOpus47) {
        _body.temperature = temp;
      }
      // v47：Opus 4.7 走 adaptive thinking + effort
      // v64.E:Opus 4.7 thinking 預設 omitted(官方 2026-04 預設值)
      //   原因:thinking 內容我們不顯示給用戶,summarized 多計費摘要 token + 多延遲
      //   omitted = 不回傳 thinking 內容,但 server 仍完整 thinking,只是直接返回最終文字
      //   效益:首字延遲 -1~3 秒、token 省 5-15%、品質不變
      if (_isOpus47 && _opts.enableThinking !== false) {
        _body.thinking = { type: 'adaptive', display: 'omitted' };
        _body.output_config = { effort: _opts.effort || 'high' };
        // ★ v62c：Task Budget（beta）——官方 2026-03 推出
        //   讓 AI 看到 token 倒數，自己規劃「第三層要寫完」
        //   官方：「model sees a running countdown and uses it to prioritize work and finish gracefully」
        //   命理場景：解決 Sonnet 4.6 在 v62b 之前塔羅第三層只做 45% 的根本問題
        //   由 admin KV 開關控制（v62c_task_budget_enabled），預設關（beta 先實測）
        if (_opts.taskBudgetEnabled === true && _opts.taskBudgetTokens) {
          _body.output_config.task_budget = {
            type: 'tokens',
            total: _opts.taskBudgetTokens
          };
          // beta header 疊加（不覆蓋現有 prompt-caching header）
          const _existingBeta = _headers['anthropic-beta'] || '';
          _headers['anthropic-beta'] = _existingBeta
            ? _existingBeta + ',task-budgets-2026-03-13'
            : 'task-budgets-2026-03-13';
        }
        // v58-hotfix4: 撤掉 _minTokens 強推邏輯——這是自己加的自作聰明保護，
        //               反而讓 max_tokens 被強推到遠大於呼叫點預期的值，
        //               thinking 吃掉大半後 text 沒空間寫完 JSON → 前端 parseJSON 失敗。
        //               呼叫點傳多少就是多少，由呼叫點根據任務類型自己決定。
        // ★ v58-hotfix：Anthropic API 新規則——adaptive thinking 啟用時 temperature 只能是 1
        //   Opus 4.7 原本就沒設 temperature（上面 if (!_isOpus47) 已排除），這邊保險起見 delete
        delete _body.temperature;
      }
      // v53：Opus 4.6 走 adaptive thinking + effort（max/high/medium/low，無 xhigh）
      // 官方說明：必須搭配 adaptive thinking，否則 effort 不生效
      // v64.E:Opus 4.6 thinking display 改 omitted(不顯示給用戶,省摘要 token)
      else if (_isOpus46 && _opts.enableThinking !== false) {
        const _eff = _opts.opus46Effort || 'high';
        _body.thinking = { type: 'adaptive', display: 'omitted' };
        _body.output_config = { effort: _eff };
        // v58-hotfix4: 撤掉 _minTokens 強推
        // ★ v58-hotfix：Anthropic API 新規則——adaptive thinking 啟用時 temperature 只能是 1
        _body.temperature = 1;
      }
      // v53：Sonnet 4.6 走 adaptive thinking + effort（max/high/medium/low，無 xhigh）
      // v58-hotfix：2026/4 起 Anthropic API 要求 adaptive thinking 時 temperature 必須是 1
      // v58-hotfix4：撤掉 _minTokens 強推
      // v64.E:Sonnet 4.6 thinking display 改 omitted(不顯示給用戶,省摘要 token)
      else if (_isSonnet46 && _opts.enableThinking !== false && _opts.sonnet46Effort) {
        const _eff = _opts.sonnet46Effort;
        _body.thinking = { type: 'adaptive', display: 'omitted' };
        _body.output_config = { effort: _eff };
        // ★ v58-hotfix：Anthropic API 新規則——adaptive thinking 啟用時 temperature 只能是 1
        _body.temperature = 1;
      }
      // ★ v49：Haiku 4.5 Extended Thinking（走舊版 budget_tokens API，與 Opus 4.7 adaptive 分流）
      // v58-hotfix：Anthropic API 新規則—— thinking 啟用時 temperature 必須為 1（涵蓋 legacy enabled 和 adaptive）
      // v58-hotfix4：保留 budget + 4000 強推——Haiku legacy thinking 是 API 硬性限制（max_tokens 必須 > budget_tokens）
      else if (_isHaiku45 && _opts.enableThinking !== false) {
        const _ht = _opts.haikuThinking || DEFAULT_HAIKU_THINKING;
        const _htEnabled = (_ht.enabled !== false);
        const _isFu = !!_opts.isFollowup;
        const _fuAllow = _isFu ? (_ht.includeFollowup !== false) : true;
        if (_htEnabled && _fuAllow) {
          var _budget = (typeof _ht.budgetTokens === 'number' && _ht.budgetTokens >= 1024 && _ht.budgetTokens <= 8000)
            ? Math.floor(_ht.budgetTokens) : 4000;
          _body.thinking = { type: 'enabled', budget_tokens: _budget };
          // Haiku legacy thinking 的硬性 API 限制：max_tokens 必須 > budget_tokens。保留此強推。
          const _minTokens = _budget + 4000;
          if (_body.max_tokens < _minTokens) _body.max_tokens = _minTokens;
          // ★ v58-hotfix：thinking 啟用時 temperature 必須為 1
          _body.temperature = 1;
        }
      }
      const resp = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: _headers,
        body: JSON.stringify(_body)
      });

      // Anthropic 過載或暫時不可用 → 等一下重試
      if ((resp.status === 529 || resp.status === 503) && attempt < maxRetries) {
        await new Promise(r => setTimeout(r, 2500 * (attempt + 1)));
        continue;
      }

      if (!resp.ok) {
        const e = await resp.text();
        // ★ debug: 把關鍵 message 欄位抽出來放最前面,確保前端 UI 截斷時仍看得到
        let _msg = '';
        let _errType = '';
        try {
          const _parsed = JSON.parse(e);
          _msg = (_parsed && _parsed.error && _parsed.error.message) ? String(_parsed.error.message) : '';
          _errType = (_parsed && _parsed.error && _parsed.error.type) ? String(_parsed.error.type) : '';
        } catch(_) {}
        // 把 message 放最前面(如果有),前端截斷時仍然看得到關鍵字
        const _prefix = _msg ? ('[' + _errType + '] ' + _msg + ' | status=' + resp.status + ' | model=' + useModel + ' | full=') : ('Anthropic ' + resp.status + ': ');
        throw new Error(_prefix + e);
      }

      // ── 讀取 Anthropic SSE stream，組裝完整回應 ──
      const reader = resp.body.getReader();
      const decoder = new TextDecoder();
      let buffer = '';
      let fullText = '';
      let usage = { input_tokens: 0, output_tokens: 0, cache_creation_input_tokens: 0, cache_read_input_tokens: 0 };
      let chunkCount = 0;

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        buffer += decoder.decode(value, { stream: true });

        // 解析 Anthropic SSE 事件
        const parts = buffer.split('\n\n');
        buffer = parts.pop(); // 最後一段可能不完整

        for (const block of parts) {
          if (!block.trim()) continue;
          const lines = block.split('\n');
          let eventType = '';
          let eventData = '';
          for (const line of lines) {
            if (line.startsWith('event: ')) eventType = line.slice(7).trim();
            else if (line.startsWith('data: ')) eventData += line.slice(6);
          }

          if (eventType === 'content_block_delta' && eventData) {
            try {
              const delta = JSON.parse(eventData);
              // v47d: 4.7 adaptive thinking 會送兩種 delta：
              // - delta.type === 'thinking_delta' → 思考摘要（送給前端顯示「思考中」）
              // - delta.type === 'text_delta' / delta.text → AI 最終答案（累積到 fullText）
              if (delta.delta?.type === 'thinking_delta' && delta.delta?.thinking) {
                // 把思考摘要透過 keepAlive 傳出（讓前端可以顯示）
                if (keepAlive) {
                  try { await keepAlive(delta.delta.thinking); } catch (_) {}
                }
              } else if (delta.delta?.text) {
                fullText += delta.delta.text;
              }
            } catch (_) {}
          } else if (eventType === 'content_block_start' && eventData) {
            // ★ v62d：Advisor Tool event 處理
            //   server_tool_use.name === 'advisor' → advisor 被呼叫，告知前端「諮詢中」
            //   advisor_tool_result → advisor 回來了，可以選擇顯示或不顯示
            //   官方：advisor 呼叫期間 stream 會暫停（advisor 本身不 stream），
            //         只有每 30 秒的 SSE ping 維持連線
            try {
              const cbs = JSON.parse(eventData);
              const cb = cbs.content_block;
              if (cb && cb.type === 'server_tool_use' && cb.name === 'advisor') {
                // advisor 開始諮詢 → 送提示給前端
                if (keepAlive) {
                  try { await keepAlive('🧙‍♂️ 正在請 Opus 顧問深度判讀...'); } catch (_) {}
                }
              } else if (cb && cb.type === 'advisor_tool_result') {
                // advisor 回來了，記錄一下但不傳內容給前端（保持 story 整潔）
                // advisor 的建議已由 Anthropic server-side 自動注入 executor 的 context
                if (keepAlive) {
                  try { await keepAlive('✓ 顧問建議已收到，繼續深入...'); } catch (_) {}
                }
              }
            } catch (_) {}
          } else if (eventType === 'message_delta' && eventData) {
            try {
              const md = JSON.parse(eventData);
              if (md.usage) {
                usage.output_tokens = md.usage.output_tokens || usage.output_tokens;
              }
            } catch (_) {}
          } else if (eventType === 'message_start' && eventData) {
            try {
              const ms = JSON.parse(eventData);
              if (ms.message?.usage) {
                usage.input_tokens = ms.message.usage.input_tokens || 0;
                usage.cache_creation_input_tokens = ms.message.usage.cache_creation_input_tokens || 0;
                usage.cache_read_input_tokens = ms.message.usage.cache_read_input_tokens || 0;
              }
            } catch (_) {}
          }

          // 每 20 個 chunk 送一次 keepalive，防止前端 SSE 連線 idle timeout
          chunkCount++;
          if (keepAlive && chunkCount % 20 === 0) {
            try { await keepAlive(); } catch (_) {}
          }
        }
      }

      // ★ v62e：Prefill 補回——【v62f-hotfix：已停用】
      //   整個 Claude 4.5+/4.6/4.7 系列都不支援 prefill，所以不會有缺開頭字元的情況
      //   原本邏輯保留註解作為歷史：
      //   if (_opts.prefillEnabled === true && _opts.prefillText && !_isOpus47 && !_isOpus46) {
      //     fullText = _opts.prefillText + fullText;
      //   }

      // ★ v22c：在源頭剝 markdown fence，parseJSON 永遠不該看到 ```
      fullText = fullText.trim();
      if (fullText.startsWith('`')) {
        fullText = fullText.replace(/^`{3,}[^\n]*\n?/, '').replace(/\n?`{3,}\s*$/, '').trim();
      }

      return { text: fullText, usage };

    } catch (err) {
      // 5xx 類 → 重試
      if (attempt < maxRetries && (/5\d\d/.test(err.message) || err.name === 'AbortError')) {
        await new Promise(r => setTimeout(r, 2500 * (attempt + 1)));
        continue;
      }
      throw err;
    }
  }
}

// ═══════════════════════════════════════════════════════════════
// v54 Best-of-N：Sonnet 對 Opus 輸出做事實核查（Claim-level verification）
// 觸發條件：isOpusDepth = true 且 admin config opus47_bestofn_config.enabled = true
// 成本：~NT$5-8/次，只對 Opus 付費流程開
// 設計：non-stream Sonnet call、10s timeout、失敗不阻塞主流程
// 輸出：{ overall, claims: [{ text, verdict, reason }], pass, fail }
// ═══════════════════════════════════════════════════════════════
async function auditOpusOutput(env, payload, result, mode) {
  // 從 result 抽 story
  const storyText = (result && (result.story || result.directAnswer || result.answer || '')) || '';
  if (!storyText || storyText.length < 100) {
    return null; // story 太短不做審計
  }

  // 從 payload 抽精簡資料當審計參考（只送關鍵欄位，不送完整 190K prompt）
  const dims = (payload && payload.dims) || {};
  const bz = dims.bazi || {};
  const zw = dims.ziwei || {};
  const vd = dims.vedic || {};
  const nt = dims.natal || {};
  const nm = dims.name || {};
  const tr = dims.tarot || {};

  const auditRef = [];
  if (bz.dayMaster) auditRef.push('八字日主: ' + bz.dayMaster);
  if (bz.fourPillars) auditRef.push('八字四柱: ' + String(bz.fourPillars).slice(0, 80));
  if (bz.favEls) auditRef.push('八字用神: ' + bz.favEls);
  if (bz.unfavEls) auditRef.push('八字忌神: ' + bz.unfavEls);
  if (bz.specialGe) auditRef.push('八字特殊格: ' + bz.specialGe);
  if (bz.geJu) auditRef.push('八字正格: ' + bz.geJu);
  if (bz.dyDetail) auditRef.push('當前大運: ' + String(typeof bz.dyDetail === 'string' ? bz.dyDetail : JSON.stringify(bz.dyDetail)).slice(0, 120));
  if (bz.lnDetail) auditRef.push('今年流年: ' + String(typeof bz.lnDetail === 'string' ? bz.lnDetail : JSON.stringify(bz.lnDetail)).slice(0, 120));
  if (zw.mingStars) auditRef.push('紫微命宮: ' + zw.mingStars);
  if (zw.keyPalaces) auditRef.push('紫微關鍵宮: ' + String(zw.keyPalaces).slice(0, 200));
  if (zw.dxDetail) auditRef.push('紫微當前大限: ' + String(zw.dxDetail).slice(0, 120));
  if (zw.geju) auditRef.push('紫微格局: ' + zw.geju);
  if (vd.lagna) auditRef.push('吠陀上升: ' + String(vd.lagna).slice(0, 60));
  if (vd.moon) auditRef.push('吠陀月亮/Nakshatra: ' + String(vd.moon).slice(0, 80));
  if (vd.dasha) auditRef.push('吠陀 Mahadasha: ' + String(vd.dasha).slice(0, 80));
  if (vd.subDasha) auditRef.push('吠陀 Antardasha: ' + String(vd.subDasha).slice(0, 80));
  if (vd.sadeSati) auditRef.push('吠陀 Sade Sati: ' + String(vd.sadeSati).slice(0, 80));
  if (vd.yogas) auditRef.push('吠陀 Yogas: ' + String(vd.yogas).slice(0, 160));
  if (nt.asc) auditRef.push('西占上升: ' + String(nt.asc).slice(0, 40));
  if (nt.transits) auditRef.push('西占行運: ' + String(nt.transits).slice(0, 160));
  if (nt.patterns) auditRef.push('西占相位格局: ' + String(nt.patterns).slice(0, 120));
  if (nm.geVsFav) auditRef.push('姓名 vs 八字: ' + String(nm.geVsFav).slice(0, 120));
  if (nm.zodiac) auditRef.push('姓名生肖: ' + String(nm.zodiac).slice(0, 80));
  if (tr.spreadType) auditRef.push('塔羅牌陣: ' + tr.spreadType);
  if (tr.outcomeCard) auditRef.push('塔羅結果牌: ' + tr.outcomeCard);

  // ★ v62f-fix：OOTK 開鑰 audit reference（之前缺失）
  // 開鑰判讀核心靠 Op1-Op5 / 代表牌 / 計數路徑 / 層間方向
  // 沒這些 audit 等於瞎判 pass，付費深度品質核查失效
  // ★ v62f-fix-2：多路徑 fallback——防未來 payload 結構改名導致 audit 失效
  //   目前前端實際只送 payload.ootkData（見 ai-analysis.js 24218 行），
  //   但 fallback 其他可能路徑當防禦式設計——零成本無副作用
  const ootkData =
    (payload && payload.ootkData) ||
    (payload && payload.tarotData && payload.tarotData.ootk) ||
    (payload && payload.dims && payload.dims.ootk) ||
    (payload && payload.ootk) ||
    null;
  if (ootkData) {
    const sig = ootkData.significator || {};
    if (sig.name || sig.id) {
      let sigStr = '開鑰代表牌: ' + (sig.name || sig.id);
      if (sig.element) sigStr += '(' + sig.element + ')';
      if (sig.gdCourt) sigStr += ' GD:' + sig.gdCourt;
      auditRef.push(sigStr);
    }
    const ops = ootkData.operations || {};
    if (ops.op1) auditRef.push('開鑰 Op1 四元素分堆: ' + String(ops.op1).slice(0, 120));
    if (ops.op2) auditRef.push('開鑰 Op2 十二宮位: ' + String(ops.op2).slice(0, 120));
    if (ops.op3) auditRef.push('開鑰 Op3 十二星座: ' + String(ops.op3).slice(0, 120));
    if (ops.op4) auditRef.push('開鑰 Op4 三十六旬(時間窗口): ' + String(ops.op4).slice(0, 140));
    if (ops.op5) auditRef.push('開鑰 Op5 生命之樹(Sephirah): ' + String(ops.op5).slice(0, 140));
    const cross = ootkData.crossAnalysis || {};
    if (cross.pileElement) auditRef.push('開鑰 活躍堆元素: ' + cross.pileElement);
    if (cross.elementFlow && typeof cross.elementFlow === 'object') {
      const ef = cross.elementFlow;
      const flowStr = [ef.op1, ef.op2, ef.op3, ef.op4, ef.op5].filter(Boolean).join(' → ');
      if (flowStr) auditRef.push('開鑰 五層元素進程: ' + flowStr);
    }
    // ── v63 C-嚴：layerAlignment + keyCardNames 是舊版自創概念 ──
    // 只在「OOTK 正統 Book T」開關關閉時才注入（fallback to legacy 行為）
    const _v63Cfg = await getV62UpgradesConfig(env);
    const _v63LegacyOK = !_v63Cfg.ootkOrthodoxBookT;
    if (_v63LegacyOK && (false /* v63E 已棄用:cross.layerAlignment */)) auditRef.push('開鑰 五層方向預判: ' + (false /* v63E 已棄用:cross.layerAlignment */));
    if ((false /* v63E 已棄用:cross.recurring */)) auditRef.push('開鑰 跨層重複牌: ' + String((false /* v63E 已棄用:cross.recurring */)).slice(0, 100));
    if (_v63LegacyOK && (false /* v63E 已棄用:cross.keyCardNames */) && (false /* v63E 已棄用:cross.keyCardNames */).length) {
      auditRef.push('開鑰 五層結論牌: ' + (false /* v63E 已棄用:cross.keyCardNames */).slice(0, 5).join('、'));
    }
    if ((false /* v63E 已棄用:cross.dominantCards */) && (false /* v63E 已棄用:cross.dominantCards */).length) {
      auditRef.push('開鑰 多層核心牌: ' + (false /* v63E 已棄用:cross.dominantCards */).slice(0, 5).map(c => String(c).slice(0, 40)).join('、'));
    }
    if (cross.conflicts && cross.conflicts.length) {
      auditRef.push('開鑰 層間衝突: ' + cross.conflicts.slice(0, 3).map(c => String(c).slice(0, 50)).join('；'));
    }
    // countingPath / pairings 是五階段推進的路徑證據
    if (ootkData.countingPath) {
      auditRef.push('開鑰 計數路徑: ' + String(typeof ootkData.countingPath === 'string' ? ootkData.countingPath : JSON.stringify(ootkData.countingPath)).slice(0, 150));
    }
    if (ootkData.pairings && Array.isArray(ootkData.pairings) && ootkData.pairings.length) {
      auditRef.push('開鑰 配對牌組: ' + ootkData.pairings.slice(0, 3).map(p => String(typeof p === 'string' ? p : JSON.stringify(p)).slice(0, 40)).join('；'));
    }
    // readability / abandon 條件
    if (ootkData.readabilityScore != null) auditRef.push('開鑰 可讀性分數: ' + ootkData.readabilityScore);
    if (ootkData.abandon) auditRef.push('開鑰 棄讀條件: ' + String(ootkData.abandon).slice(0, 100));
  }
  // ★ v62f-fix end

  const auditSystem = '你是命理輸出事實核查員。任務：從下方 Opus 產出的 story 裡，抽出所有「具體宣稱」，逐條對照「命盤原始數據」檢查是否有依據。\n\n具體宣稱 = 以下六類之一：\n① 具體年份（2026、2028）\n② 具體月份/季度（3月、Q3、下半年）\n③ 具體人物畫像（35-40歲、金融業、個性主動）\n④ 具體事件預測（分手、搬家、升遷、懷孕）\n⑤ 具體格局/星名（Raj Yoga、殺破狼、Ketu 在 8 宮、七殺在命宮）\n⑥ 具體金額/數量\n\n每一條判定三選一：\n- pass（有 ≥1 個命盤欄位明確支撐，斷言可信）\n- soft（推論合理但只有 1 個弱證據，建議降級為「傾向」「可能」）\n- fail（找不到任何命盤欄位支撐，可能是 training data 腦補）\n\n只在 story 真的有「具體宣稱」時才列出。純粹的情緒安撫、一般性建議、抽象描述不算具體宣稱，不列。\n\n最多抽 8 條（優先抽最具體、最可能被用戶截圖分享的判斷）。每條 claim 文字從 story 原文截取，不超過 60 字。\n\n必須輸出嚴格的 JSON 格式（不要 markdown 代碼框）：\n{\n  "claims": [\n    { "text": "story原文片段", "verdict": "pass|soft|fail", "reason": "對到哪個欄位 or 為什麼不對" }\n  ],\n  "pass_count": 數字,\n  "soft_count": 數字,\n  "fail_count": 數字,\n  "overall": "清楚/部分/不通過"\n}\n\n判斷標準寬鬆原則：如果 Opus 用了「傾向」「可能」「方向」「有機會」這類軟性語言 → 通常 pass，不要吹毛求疵。只有用了篤定口氣（「你今年會」「他就是」「3 月一定」）但命盤沒依據時才 fail。\n';

  const auditUser = '═══ 命盤原始數據（核查依據）═══\n' + auditRef.join('\n') + '\n\n═══ Opus 產出的 story（被核查對象）═══\n' + storyText + '\n\n依系統提示執行核查，只輸出 JSON。';

  // 10s timeout 控制
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 10000);

  try {
    const rsp = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01'
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-6',
        max_tokens: 1800,
        temperature: 0.1,  // 核查任務用低溫
        thinking: { type: 'disabled' },  // 不啟用 thinking 節省時間
        output_config: { effort: 'low' },
        system: auditSystem,
        messages: [{ role: 'user', content: auditUser }]
      }),
      signal: controller.signal
    });
    clearTimeout(timeoutId);

    if (!rsp.ok) return null;
    const data = await rsp.json();
    const txt = (data && data.content && data.content[0] && data.content[0].text) || '';
    if (!txt) return null;

    // 嘗試 parse JSON
    let parsed = null;
    try {
      // 移除可能的 markdown 代碼框
      const cleaned = txt.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```\s*$/i, '').trim();
      parsed = JSON.parse(cleaned);
    } catch (_je) {
      // 嘗試抽出 {...} 區塊
      const m = txt.match(/\{[\s\S]*\}/);
      if (m) {
        try { parsed = JSON.parse(m[0]); } catch (_je2) {}
      }
    }
    if (!parsed || !Array.isArray(parsed.claims)) return null;

    // 附加 usage 統計（僅供 admin 觀察成本）
    const _usage = (data && data.usage) || {};
    parsed._usage = {
      in: _usage.input_tokens || 0,
      out: _usage.output_tokens || 0
    };

    return parsed;
  } catch (_err) {
    clearTimeout(timeoutId);
    return null; // 任何錯誤都不阻塞主流程
  }
}

// ═══ v38：照片 content block 建構器 ═══
// 如果 payload.photos 有圖片，把文字訊息和圖片合成 content array
// Anthropic API content 接受 string 或 [{type:'text',...},{type:'image',...}] 陣列
function buildMessageWithPhotos(textMessage, payload) {
  var photos = (payload && payload.photos) || {};
  var hasAny = photos.face || photos.palmLeft || photos.palmRight || photos.crystal;
  if (!hasAny) return textMessage; // 沒照片就回傳原始字串

  var content = [];

  // 照片放在最前面，讓 AI 先看到圖再讀數據
  var photoLabels = { face: '【用戶臉部照片】', palmLeft: '【用戶左手掌照片】', palmRight: '【用戶右手掌照片】', crystal: '【用戶水晶照片】' };
  var order = ['face', 'palmLeft', 'palmRight', 'crystal'];
  for (var _pi = 0; _pi < order.length; _pi++) {
    var _pk = order[_pi];
    if (photos[_pk]) {
      content.push({ type: 'text', text: photoLabels[_pk] });
      // 前端送的是 data:image/jpeg;base64,xxxx 格式，需要拆出 media_type 和 data
      var _imgData = String(photos[_pk]);
      var _mediaType = 'image/jpeg';
      var _base64 = _imgData;
      if (_imgData.indexOf('data:') === 0) {
        var _semi = _imgData.indexOf(';');
        var _comma = _imgData.indexOf(',');
        if (_semi > 0) _mediaType = _imgData.substring(5, _semi);
        if (_comma > 0) _base64 = _imgData.substring(_comma + 1);
      }
      content.push({
        type: 'image',
        source: { type: 'base64', media_type: _mediaType, data: _base64 }
      });
    }
  }

  // 文字訊息放在圖片後面
  content.push({ type: 'text', text: textMessage });

  return content;
}

function _fixJsonStringNewlines(s) {
  var result = '', inStr = false, esc = false;
  for (var i = 0; i < s.length; i++) {
    var ch = s[i];
    if (esc) { result += ch; esc = false; continue; }
    if (ch === '\\' && inStr) { result += ch; esc = true; continue; }
    if (ch === '"') { inStr = !inStr; result += ch; continue; }
    if (inStr) {
      if (ch === '\n') { result += '\\n'; continue; }
      if (ch === '\r') { result += '\\r'; continue; }
      if (ch === '\t') { result += '\\t'; continue; }
    }
    result += ch;
  }
  return result;
}

function parseJSON(raw) {
  let c = String(raw || '').trim();
  if (!c) return {};

  // Step 1: 直接試
  try { return JSON.parse(c); } catch(_) {}

  // Step 2: 去 fence → 抽 {...} → 殺控制字元 → parse
  // 舊版 bug：fence regex 在邊界條件失敗 → 控制字元替換後 ```json 殘留 → 全炸
  // 新版：先殺控制字元，再用 indexOf 找 {和}，一刀切
  let clean = c.replace(/[\x00-\x1F]+/g, ' ');
  const fi = clean.indexOf('{');
  const li = clean.lastIndexOf('}');
  if (fi === -1 || li <= fi) return { answer: c, _parseFailed: true };
  clean = clean.slice(fi, li + 1);

  try { return JSON.parse(clean); } catch(_) {}

  // 去 trailing comma
  clean = clean.replace(/,\s*([\]}])/g, '$1');
  try { return JSON.parse(clean); } catch(_) {}

  // 截斷修復：AI 被 max_tokens 截斷 → 關閉未完成字串 + 補齊括號
  // 先關字串，再從尾巴往前找可 parse 的點
  let truncFixed = clean;
  // 計算未閉合的引號（簡易：數引號奇偶）
  let quoteCount = 0;
  for (let q = 0; q < truncFixed.length; q++) {
    if (truncFixed[q] === '"' && (q === 0 || truncFixed[q-1] !== '\\')) quoteCount++;
  }
  if (quoteCount % 2 !== 0) truncFixed += '"'; // 關閉未完成字串
  // 補齊括號
  let depth = { brace: 0, bracket: 0 };
  let inStr = false, esc = false;
  for (let q = 0; q < truncFixed.length; q++) {
    let ch = truncFixed[q];
    if (esc) { esc = false; continue; }
    if (ch === '\\' && inStr) { esc = true; continue; }
    if (ch === '"') { inStr = !inStr; continue; }
    if (!inStr) {
      if (ch === '{') depth.brace++;
      else if (ch === '}') depth.brace--;
      else if (ch === '[') depth.bracket++;
      else if (ch === ']') depth.bracket--;
    }
  }
  // 去尾部殘留的逗號/冒號
  truncFixed = truncFixed.replace(/[,:]\s*$/, '');
  for (let q = 0; q < depth.bracket; q++) truncFixed += ']';
  for (let q = 0; q < depth.brace; q++) truncFixed += '}';
  try { 
    const truncResult = JSON.parse(truncFixed);
    if (truncResult && (truncResult.directAnswer || truncResult.layers)) return truncResult;
  } catch(_) {}

  // 最後手段：從尾巴往前找可 parse 的 }
  for (let i = clean.length - 1; i > 100; i--) {
    if (clean[i] === '}') {
      try { return JSON.parse(clean.slice(0, i + 1)); } catch(_) { continue; }
    }
  }

  return { answer: c, _parseFailed: true };
}

function toArray(v) {
  if (Array.isArray(v)) return v.filter(Boolean);
  if (v == null || v === '') return [];
  return [v];
}

function renderValue(v) {
  if (v == null || v === '') return '';
  if (typeof v === 'string') return v.trim();
  if (typeof v === 'number' || typeof v === 'boolean') return String(v);
  if (Array.isArray(v)) return v.map(renderValue).filter(Boolean).join('；');
  if (typeof v === 'object') {
    return Object.entries(v)
      .filter(([, value]) => value != null && value !== '' && !(Array.isArray(value) && !value.length))
      .map(([k, value]) => `${k}: ${renderValue(value)}`)
      .join('；');
  }
  return String(v);
}

// ★ v13：renderSystemPayload / addSection / addListSection 已移除（死碼，無人呼叫）

// ═══ v44b：後台可配模型切換——每套命理可獨立選「標準/深度」兩模型，4 模型任選 ═══
// KV key: model_config → JSON
//   新結構: { "7d":{std,deep}, "tarot":{std,deep}, "ootk":{std,deep} }
//   舊結構(v43): { "7d":"...", "tarot":"...", "ootk":"...", "opus":"..." } → 自動遷移
// 預設 fallback: std=sonnet-4-6, deep=opus-4-6
const MODEL_OPTIONS_ALL = {
  'claude-sonnet-4-6': 'claude-sonnet-4-6',
  'claude-haiku-4-5':  'claude-haiku-4-5',
  'claude-opus-4-6':   'claude-opus-4-6',
  'claude-opus-4-7':   'claude-opus-4-7'
};
// v44b：所有 6 個 select 都能選任一模型（不再限制深度只能 opus）
const DEFAULT_STD_MODEL  = 'claude-sonnet-4-6';
const DEFAULT_DEEP_MODEL = 'claude-opus-4-6';

function _normalizeToolCfg(tool) {
  if (tool && typeof tool === 'object') {
    var _std  = MODEL_OPTIONS_ALL[tool.std]  || DEFAULT_STD_MODEL;
    var _deep = MODEL_OPTIONS_ALL[tool.deep] || DEFAULT_DEEP_MODEL;
    // v47：追問獨立 slot，未設定時 fallback 到 std
    var _fu   = MODEL_OPTIONS_ALL[tool.fu]   || _std;
    return { std: _std, deep: _deep, fu: _fu };
  }
  // 舊結構自動遷移：tool 是單一字串 → 視為 std，deep 用預設，fu=std
  if (typeof tool === 'string' && MODEL_OPTIONS_ALL[tool]) {
    return { std: MODEL_OPTIONS_ALL[tool], deep: DEFAULT_DEEP_MODEL, fu: MODEL_OPTIONS_ALL[tool] };
  }
  return { std: DEFAULT_STD_MODEL, deep: DEFAULT_DEEP_MODEL, fu: DEFAULT_STD_MODEL };
}

// v44c：分用戶類型的工具配置——支援多格式向後相容
// v62 格式：{ free:{std,deep,fu}, member:{std,deep,fu}, premium:{std,deep,fu}, paid:{std,deep,fu} }
// v47 格式：{ free, member, paid }（三類） → premium 自動 fallback 到 member
// v44c 格式：{ free:{std,deep}, member:{std,deep}, paid:{std,deep} }  → fu 自動補為 std
// v44b 舊格式：{ std, deep } → 所有用戶類型共用
// 最舊格式：單一字串
function _normalizeToolCfgByUserType(tool) {
  if (tool && typeof tool === 'object') {
    // 新格式：已分 free/member/premium/paid
    if (tool.free || tool.member || tool.premium || tool.paid) {
      var _free   = _normalizeToolCfg(tool.free   || {});
      var _member = _normalizeToolCfg(tool.member || {});
      // v62：premium 缺省時 fallback 到 member（向後相容 v47 三類結構）
      var _premium = tool.premium ? _normalizeToolCfg(tool.premium) : _member;
      var _paid   = _normalizeToolCfg(tool.paid   || {});
      return { free: _free, member: _member, premium: _premium, paid: _paid };
    }
    // 舊格式：{ std, deep } → 四個用戶類型共用同一配置
    var shared = _normalizeToolCfg(tool);
    return { free: shared, member: shared, premium: shared, paid: shared };
  }
  // 最舊格式：單一字串
  if (typeof tool === 'string' && MODEL_OPTIONS_ALL[tool]) {
    var legacy = { std: MODEL_OPTIONS_ALL[tool], deep: DEFAULT_DEEP_MODEL, fu: MODEL_OPTIONS_ALL[tool] };
    return { free: legacy, member: legacy, premium: legacy, paid: legacy };
  }
  var def = { std: DEFAULT_STD_MODEL, deep: DEFAULT_DEEP_MODEL, fu: DEFAULT_STD_MODEL };
  return { free: def, member: def, premium: def, paid: def };
}

// ═══ v44：動態定價表——從 KV 讀，允許 admin 自由設定 ═══
// KV key: model_pricing → JSON { "claude-sonnet-4-6": {in:3,out:15,cacheRead:0.3,cacheWrite:3.75}, ... }
// 預設值對齊 2026/4 官方 API 定價
const DEFAULT_PRICING = {
  'claude-sonnet-4-6':  { in: 3,    out: 15, cacheRead: 0.30, cacheWrite: 3.75 },
  'claude-haiku-4-5':   { in: 1,    out:  5, cacheRead: 0.10, cacheWrite: 1.25 },
  'claude-opus-4-6':    { in: 5,    out: 25, cacheRead: 0.50, cacheWrite: 6.25 },
  'claude-opus-4-7':    { in: 5,    out: 25, cacheRead: 0.50, cacheWrite: 6.25 }
};
const DEFAULT_USD_TO_TWD = 32;

async function getModelConfig(env) {
  // v62：新結構——每個工具分 free/member/premium/paid 四類用戶，每類有 std/deep/fu
  const _defaultPerUser = { std: DEFAULT_STD_MODEL, deep: DEFAULT_DEEP_MODEL, fu: DEFAULT_STD_MODEL };
  const _fallback = {
    '7d':    { free: _defaultPerUser, member: _defaultPerUser, premium: _defaultPerUser, paid: _defaultPerUser },
    tarot:   { free: _defaultPerUser, member: _defaultPerUser, premium: _defaultPerUser, paid: _defaultPerUser },
    ootk:    { free: _defaultPerUser, member: _defaultPerUser, premium: _defaultPerUser, paid: _defaultPerUser }
  };
  if (!env.RATE_KV) return _fallback;
  try {
    const raw = await env.RATE_KV.get('model_config');
    if (raw) {
      const cfg = JSON.parse(raw);
      return {
        '7d':  _normalizeToolCfgByUserType(cfg['7d']),
        tarot: _normalizeToolCfgByUserType(cfg.tarot),
        ootk:  _normalizeToolCfgByUserType(cfg.ootk)
      };
    }
  } catch(_) {}
  return _fallback;
}

// v44c：根據用戶類型和深度模式挑出正確的模型 id
// v47：新增 forFollowup 參數——追問走 fu slot（fallback std）
// v62：支援四級用戶類型，含 premium 高級會員與多級 fallback
// tool: '7d' | 'tarot' | 'ootk'
// userType: 'free' | 'member' | 'premium' | 'paid'
// isOpusDepth: boolean
// forFollowup: boolean（true 時優先 fu，忽略 isOpusDepth；fu 缺時 fallback std）
//
// fallback 順序（防 KV 是舊結構時也能跑）：
//   premium → member → free
//   member  → free
//   paid    → free
function pickModel(baseModels, tool, userType, isOpusDepth, forFollowup) {
  var toolCfg = baseModels[tool];
  if (!toolCfg) return forFollowup ? DEFAULT_STD_MODEL : (isOpusDepth ? DEFAULT_DEEP_MODEL : DEFAULT_STD_MODEL);
  var userCfg = toolCfg[userType];
  if (!userCfg) {
    // v62：依用戶類型逐級 fallback
    if (userType === 'premium') userCfg = toolCfg.member || toolCfg.free;
    else if (userType === 'member' || userType === 'paid') userCfg = toolCfg.free;
    else userCfg = toolCfg.free;
  }
  if (!userCfg) userCfg = { std: DEFAULT_STD_MODEL, deep: DEFAULT_DEEP_MODEL, fu: DEFAULT_STD_MODEL };
  if (forFollowup) return userCfg.fu || userCfg.std || DEFAULT_STD_MODEL;
  return isOpusDepth ? userCfg.deep : userCfg.std;
}

// 讀取動態定價表（若 KV 中有自訂值則用之，否則 fallback 預設）
async function getPricingConfig(env) {
  const result = { pricing: JSON.parse(JSON.stringify(DEFAULT_PRICING)), usdToTwd: DEFAULT_USD_TO_TWD };
  if (!env.RATE_KV) return result;
  try {
    const raw = await env.RATE_KV.get('model_pricing');
    if (raw) {
      const cfg = JSON.parse(raw);
      if (cfg.pricing && typeof cfg.pricing === 'object') {
        // 逐個模型合併（KV 的值覆蓋預設）
        Object.keys(cfg.pricing).forEach(function(mdl) {
          const p = cfg.pricing[mdl];
          if (p && typeof p === 'object') {
            result.pricing[mdl] = {
              in: typeof p.in === 'number' ? p.in : (result.pricing[mdl] || {}).in || 0,
              out: typeof p.out === 'number' ? p.out : (result.pricing[mdl] || {}).out || 0,
              cacheRead: typeof p.cacheRead === 'number' ? p.cacheRead : (result.pricing[mdl] || {}).cacheRead || 0,
              cacheWrite: typeof p.cacheWrite === 'number' ? p.cacheWrite : (result.pricing[mdl] || {}).cacheWrite || 0
            };
          }
        });
      }
      if (typeof cfg.usdToTwd === 'number' && cfg.usdToTwd > 0) result.usdToTwd = cfg.usdToTwd;
    }
  } catch(_) {}
  return result;
}

function detectFocusType(question) {
  const q = safeString(question);
  if (/曖昧|復合|感情|喜歡|桃花|對象|交往|第三者|出軌|前任|婚姻|同居|戀|暗戀|追|正緣|分手|男友|女友|老公|老婆|另一半|love|relationship|partner|boyfriend|girlfriend|marriage|crush/i.test(q)) return 'love';
  if (/工作|事業|升遷|轉職|主管|同事|離職|創業|合作|面試|公司|職場|上班|career|job|promotion|business|work/i.test(q)) return 'career';
  if (/財運|收入|投資|賺錢|副業|金錢|現金流|股票|基金|理財|開店|money|wealth|invest|income|finance/i.test(q)) return 'wealth';
  if (/家庭|父母|小孩|親人|家人|親子|婆媳|family|parents|children/i.test(q)) return 'family';
  if (/健康|身體|情緒|失眠|壓力|焦慮|疲累|生病|手術|health|anxiety|stress|sleep/i.test(q)) return 'health';
  if (/人際|朋友|社交|貴人|小人|friends|social/i.test(q)) return 'relationship';
  return 'general';
}


function formatQuestionDecomposition(qd) {
  if (!qd || typeof qd !== 'object') return '（無法拆解，後續請依原問題自行逐題辨識）';
  const lines = [];
  if (qd.topic) lines.push('topic: ' + qd.topic);
  if (qd.surface_question) lines.push('surface_question: ' + qd.surface_question);
  if (qd.core_need) lines.push('core_need: ' + qd.core_need);
  const subs = Array.isArray(qd.subquestions) ? qd.subquestions : [];
  if (subs.length) {
    lines.push('subquestions:');
    subs.forEach((sq, idx) => {
      const q = safeString(sq.question) || `子題${idx + 1}`;
      const type = safeString(sq.type) || '未分類';
      const pri = sq.priority != null ? `priority=${sq.priority}` : '';
      const primary = sq.is_primary ? 'primary' : 'secondary';
      const need = safeString(sq.implicit_need);
      lines.push(`- ${(sq.id || ('q' + (idx + 1)))}｜${q}｜${type}｜${primary}${pri ? '｜' + pri : ''}${need ? '｜implicit_need=' + need : ''}`);
    });
  }
  if (Array.isArray(qd.answer_strategy) && qd.answer_strategy.length) {
    lines.push('answer_strategy:');
    qd.answer_strategy.forEach(s => lines.push('- ' + renderValue(s)));
  }
  return lines.join('\n');
}

