        const current = await getMaxTokensConfig(env);
        const newCfg = Object.assign({}, current);
        const rejected = [];
        for (const k of MAX_TOKENS_KEYS) {
          if (typeof body[k] === 'number') {
            const v = Math.floor(body[k]);
            if (v >= MAX_TOKENS_LIMITS.min && v <= MAX_TOKENS_LIMITS.max) {
              newCfg[k] = v;
            } else {
              rejected.push(k + '=' + body[k] + ' (out of ' + MAX_TOKENS_LIMITS.min + '-' + MAX_TOKENS_LIMITS.max + ')');
            }
          }
        }
        await env.RATE_KV.put('max_tokens_config', JSON.stringify(newCfg));
        return Response.json({ ok: true, config: newCfg, rejected: rejected }, { headers: cors });
